1	/**
2	 * Mixer audio graph engine.
3	 * Per-track channel strips -> master bus -> brickwall limiter -> destination.
4	 *
5	 * INV-2: Non-bypassable DynamicsCompressorNode as brickwall limiter
6	 * (threshold=-1dBFS, ratio=20:1, knee=0, attack=0.001s)
7	 */
8	
9	import type { ChannelStrip, MasterBus, MixerEngine } from "./types";
10	import { createInsertChain, type InsertChain } from "./insert-chain";
11	
12	function clamp(v: number, min: number, max: number): number {
13	  return Math.min(max, Math.max(min, v));
14	}
15	
16	/**
17	 * Quadratic fader taper: attempt to model a real mixing console fader.
18	 * Maps linear 0..2 -> gain curve.
19	 * 0 -> 0 (silence), 1 -> 1 (unity), 2 -> 2 (boost)
20	 */
21	function faderTaper(linear: number): number {
22	  if (linear <= 0) return 0;
23	  if (linear <= 1) {
24	    // Attempt log curve: x^2 gives reasonable taper for 0..1
25	    return linear * linear;
26	  }
27	  // Above unity: linear interpolation from 1..2
28	  return 1 + (linear - 1);
29	}
30	
31	function createMasterBus(ctx: AudioContext): MasterBus {
32	  const inputGain = ctx.createGain();
33	  const faderGain = ctx.createGain();
34	  const limiter = ctx.createDynamicsCompressor();
35	  const analyser = ctx.createAnalyser();
36	
37	  // INV-2: Brickwall limiter settings
38	  limiter.threshold.value = -1;
39	  limiter.ratio.value = 20;
40	  limiter.knee.value = 0;
41	  limiter.attack.value = 0.001;
42	  limiter.release.value = 0.01;
43	
44	  // Chain: inputGain -> faderGain -> limiter -> analyser -> destination
45	  inputGain.connect(faderGain);
46	  faderGain.connect(limiter);
47	  limiter.connect(analyser);
48	  analyser.connect(ctx.destination);
49	
50	  return { inputGain, faderGain, limiter, analyser };
51	}
52	
53	function createChannelStrip(
54	  ctx: AudioContext,
55	  trackId: string,
56	  masterInput: GainNode,
57	): ChannelStrip {
58	  const inputGain = ctx.createGain();
59	  const preFaderTap = ctx.createGain(); // Unity gain tap for pre-fader sends
60	  const faderGain = ctx.createGain();
61	  const panner = ctx.createStereoPanner();
62	  const muteGain = ctx.createGain();
63	  const analyser = ctx.createAnalyser();
64	
65	  // Chain: inputGain -> [insert chain] -> preFaderTap -> faderGain -> panner -> muteGain -> analyser -> master input
66	  // Note: inputGain -> preFaderTap connection is managed by the insert chain
67	  preFaderTap.connect(faderGain);
68	  faderGain.connect(panner);
69	  panner.connect(muteGain);
70	  muteGain.connect(analyser);
71	  analyser.connect(masterInput);
72	
73	  return {
74	    trackId,
75	    inputGain,
76	    inserts: [],
77	    preFaderTap,
78	    faderGain,
79	    panner,
80	    muteGain,
81	    analyser,
82	    muted: false,
83	    solo: false,
84	    soloIsolate: false,
85	  };
86	}
87	
88	export function createMixerEngine(ctx: AudioContext): MixerEngine {
89	  const master = createMasterBus(ctx);
90	  const strips = new Map<string, ChannelStrip>();
91	  const insertChains = new Map<string, InsertChain>();
92	  let savedMasterLevel = 1;
93	
94	  function applyMuteState(strip: ChannelStrip): void {
95	    const hasSolo = [...strips.values()].some((s) => s.solo);
96	
97	    if (strip.muted) {
98	      strip.muteGain.gain.value = 0;
99	      return;
100	    }
101	
102	    if (hasSolo) {
103	      if (strip.solo || strip.soloIsolate) {
104	        strip.muteGain.gain.value = 1;
105	      } else {
106	        strip.muteGain.gain.value = 0;
107	      }
108	    } else {
109	      strip.muteGain.gain.value = 1;
110	    }
111	  }
112	
113	  const engine: MixerEngine = {
114	    getOrCreateStrip(trackId: string): ChannelStrip {
115	      const existing = strips.get(trackId);
116	      if (existing) return existing;
117	
118	      const strip = createChannelStrip(ctx, trackId, master.inputGain);
119	      strips.set(trackId, strip);
120	      // Insert chain between inputGain and preFaderTap
121	      const chain = createInsertChain(strip.inputGain, strip.preFaderTap);
122	      insertChains.set(trackId, chain);
123	      return strip;
124	    },
125	
126	    removeStrip(trackId: string): void {
127	      const strip = strips.get(trackId);
128	      if (!strip) return;
129	
130	      const chain = insertChains.get(trackId);
131	      chain?.dispose();
132	      insertChains.delete(trackId);
133	
134	      strip.inputGain.disconnect();
135	      strip.preFaderTap.disconnect();
136	      strip.faderGain.disconnect();
137	      strip.panner.disconnect();
138	      strip.muteGain.disconnect();
139	      strip.analyser.disconnect();
140	      strips.delete(trackId);
141	    },
142	
143	    getStrip(trackId: string): ChannelStrip | undefined {
144	      return strips.get(trackId);
145	    },
146	
147	    getAllStrips(): readonly ChannelStrip[] {
148	      return [...strips.values()];
149	    },
150	
151	    getMaster(): MasterBus {
152	      return master;
153	    },
154	
155	    setFaderLevel(trackId: string, level: number): void {
156	      const strip = strips.get(trackId);
157	      if (!strip) return;
158	      const clamped = clamp(level, 0, 2);
159	      strip.faderGain.gain.value = faderTaper(clamped);
160	    },
161	
162	    setPan(trackId: string, pan: number): void {
163	      const strip = strips.get(trackId);
164	      if (!strip) return;
165	      strip.panner.pan.value = clamp(pan, -1, 1);
166	    },
167	
168	    setMute(trackId: string, muted: boolean): void {
169	      const strip = strips.get(trackId);
170	      if (!strip) return;
171	      strip.muted = muted;
172	      applyMuteState(strip);
173	    },
174	
175	    setSolo(trackId: string, solo: boolean): void {
176	      const strip = strips.get(trackId);
177	      if (!strip) return;
178	      strip.solo = solo;
179	      engine.updateSoloState();
180	    },
181	
182	    setSoloIsolate(trackId: string, enabled: boolean): void {
183	      const strip = strips.get(trackId);
184	      if (!strip) return;
185	      strip.soloIsolate = enabled;
186	      engine.updateSoloState();
187	    },
188	
189	    updateSoloState(): void {
190	      for (const strip of strips.values()) {
191	        applyMuteState(strip);
192	      }
193	    },
194	
195	    setMasterLevel(level: number): void {
196	      savedMasterLevel = clamp(level, 0, 2);
197	      master.faderGain.gain.value = savedMasterLevel;
198	    },
199	
200	    getTrackInput(trackId: string): AudioNode {
201	      return engine.getOrCreateStrip(trackId).inputGain;
202	    },
203	
204	    addInsert(
205	      trackId: string,
206	      id: string,
207	      input: AudioNode,
208	      output: AudioNode,
209	    ): void {
210	      const chain = insertChains.get(trackId);
211	      chain?.addInsert(id, input, output);
212	    },
213	
214	    replaceInsert(
215	      trackId: string,
216	      id: string,
217	      input: AudioNode,
218	      output: AudioNode,
219	    ): void {
220	      const chain = insertChains.get(trackId);
221	      chain?.replaceInsert(id, input, output);
222	    },
223	
224	    removeInsert(trackId: string, insertId: string): void {
225	      const chain = insertChains.get(trackId);
226	      chain?.removeInsert(insertId);
227	    },
228	
229	    emergencyMute(): void {
230	      master.faderGain.gain.value = 0;
231	    },
232	
233	    releaseEmergencyMute(): void {
234	      master.faderGain.gain.value = savedMasterLevel;
235	    },
236	
237	    dispose(): void {
238	      for (const chain of insertChains.values()) {
239	        chain.dispose();
240	      }
241	      insertChains.clear();
242	      for (const strip of strips.values()) {
243	        strip.inputGain.disconnect();
244	        strip.preFaderTap.disconnect();
245	        strip.faderGain.disconnect();
246	        strip.panner.disconnect();
247	        strip.muteGain.disconnect();
248	        strip.analyser.disconnect();
249	      }
250	      strips.clear();
251	      master.inputGain.disconnect();
252	      master.faderGain.disconnect();
253	      master.limiter.disconnect();
254	      master.analyser.disconnect();
255	    },
256	  };
257	
258	  return engine;
259	}
