2	 * Pure functions for automation curve evaluation and point manipulation.
3	 * All operations are immutable - they return new arrays.
4	 */
5	
6	import type { AutomationPoint, ParameterRange } from "./automation-types";
7	
8	/**
9	 * Evaluate an automation curve at a given time position.
10	 * Returns normalized value (0..1).
11	 *
12	 * - Before first point: holds first point value
13	 * - After last point: holds last point value
14	 * - Between points: interpolates based on left point's interpolation mode
15	 */
16	export function evaluateCurve(
17	  points: readonly AutomationPoint[],
18	  time: number,
19	): number {
20	  const first = points[0];
21	  if (!first) return 0;
22	  if (points.length === 1) return first.value;
23	
24	  // Before first point
25	  if (time <= first.time) return first.value;
26	
27	  // After last point
28	  const last = points[points.length - 1];
29	  if (!last || time >= last.time) return last?.value ?? 0;
30	
31	  // Find segment: binary search for left point
32	  let lo = 0;
33	  let hi = points.length - 1;
34	  while (lo < hi - 1) {
35	    const mid = (lo + hi) >>> 1;
36	    const midPoint = points[mid];
37	    if (midPoint && midPoint.time <= time) {
38	      lo = mid;
39	    } else {
40	      hi = mid;
41	    }
42	  }
43	
44	  const left = points[lo];
45	  const right = points[hi];
46	  if (!left || !right) return 0;
47	
48	  // Compute parameter t within segment
49	  const dt = right.time - left.time;
50	  if (dt === 0) return left.value;
51	  const t = (time - left.time) / dt;
52	
53	  if (left.interpolation === "linear" || left.curve === 0) {
54	    return left.value + (right.value - left.value) * t;
55	  }
56	
57	  // Curved interpolation: exponential-style curve using power function
58	  // curve > 0 = convex (fast start), curve < 0 = concave (slow start)
59	  const shapedT = shapeCurve(t, left.curve);
60	  return left.value + (right.value - left.value) * shapedT;
61	}
62	
63	/**
64	 * Shape a linear t (0..1) using a curve parameter (-1..1).
65	 * Positive curve = convex (fast start, slow end).
66	 * Negative curve = concave (slow start, fast end).
67	 * Zero = linear.
68	 */
69	function shapeCurve(t: number, curve: number): number {
70	  if (curve === 0) return t;
71	  // Map curve (-1..1) to exponent: curve=-1 -> exp=3, curve=0 -> exp=1, curve=1 -> exp=1/3
72	  const exponent = Math.pow(3, -curve);
73	  return Math.pow(t, exponent);
74	}
75	
76	/** Map normalized value (0..1) to actual parameter range, clamped */
77	export function denormalize(normalized: number, range: ParameterRange): number {
78	  const val = range.min + normalized * (range.max - range.min);
79	  return Math.max(range.min, Math.min(range.max, val));
80	}
81	
82	/** Map actual parameter value to normalized (0..1), clamped */
83	export function normalize(value: number, range: ParameterRange): number {
84	  const span = range.max - range.min;
85	  if (span === 0) return 0;
86	  return Math.max(0, Math.min(1, (value - range.min) / span));
87	}
88	
89	/** Clamp a point's time and value to valid ranges */
90	function clampPoint(point: AutomationPoint): AutomationPoint {
91	  const time = Math.max(0, point.time);
92	  const value = Math.max(0, Math.min(1, point.value));
93	  if (time === point.time && value === point.value) return point;
94	  return { ...point, time, value };
95	}
96	
97	/** Insert a point maintaining time-sorted order (immutable) */
98	export function insertPoint(
99	  points: readonly AutomationPoint[],
100	  point: AutomationPoint,
101	): readonly AutomationPoint[] {
102	  const clamped = clampPoint(point);
103	  const idx = points.findIndex((p) => p.time > clamped.time);
104	  if (idx === -1) return [...points, clamped];
105	  return [...points.slice(0, idx), clamped, ...points.slice(idx)];
106	}
107	
108	/** Remove a point by id (immutable) */
109	export function removePoint(
110	  points: readonly AutomationPoint[],
111	  pointId: string,
112	): readonly AutomationPoint[] {
113	  const filtered = points.filter((p) => p.id !== pointId);
114	  return filtered.length === points.length ? points : filtered;
115	}
116	
117	/** Move a point to new time/value, re-sorting by time (immutable) */
118	export function movePoint(
119	  points: readonly AutomationPoint[],
120	  pointId: string,
121	  newTime: number,
122	  newValue: number,
123	): readonly AutomationPoint[] {
124	  const idx = points.findIndex((p) => p.id === pointId);
125	  if (idx === -1) return points;
126	  const existing = points[idx];
127	  if (!existing) return points;
128	  const updated: AutomationPoint = {
129	    ...existing,
130	    time: Math.max(0, newTime),
131	    value: Math.max(0, Math.min(1, newValue)),
132	  };
133	  const without = [...points.slice(0, idx), ...points.slice(idx + 1)];
134	  return insertPoint(without, updated);
135	}
136	
137	/** Find all points with time in (start, end) exclusive, using binary search */
138	export function findPointsInRange(
139	  points: readonly AutomationPoint[],
140	  start: number,
141	  end: number,
142	): readonly AutomationPoint[] {
143	  if (points.length === 0) return [];
144	  // Binary search for first point with time > start
145	  let lo = 0;
146	  let hi = points.length;
147	  while (lo < hi) {
148	    const mid = (lo + hi) >>> 1;
149	    const pt = points[mid];
150	    if (pt && pt.time <= start) lo = mid + 1;
151	    else hi = mid;
152	  }
153	  const result: AutomationPoint[] = [];
154	  for (let i = lo; i < points.length; i++) {
155	    const pt = points[i];
156	    if (!pt || pt.time >= end) break;
157	    result.push(pt);
158	  }
159	  return result;
160	}
