1	/**
2	 * Look-ahead scheduler using the Chris Wilson pattern:
3	 * setInterval fires every ~25ms, scheduling audio events
4	 * that fall within the next 100ms of AudioContext time.
5	 *
6	 * This runs on the main thread. The setInterval callback is lightweight
7	 * (just math + scheduling calls), so it doesn't block rendering.
8	 */
9	
10	import type { TransportClock } from "./transport-clock";
11	
12	export type SchedulerConfig = {
13	  intervalMs: number;
14	  lookAheadMs: number;
15	};
16	
17	export type LookAheadScheduler = {
18	  start(): void;
19	  stop(): void;
20	  /** Re-sync beat phase to the current clock position (e.g. after seek). */
21	  sync(): void;
22	  readonly isRunning: boolean;
23	};
24	
25	const DEFAULT_CONFIG: SchedulerConfig = {
26	  intervalMs: 25,
27	  lookAheadMs: 100,
28	};
29	
30	export function createLookAheadScheduler(
31	  ctx: AudioContext,
32	  clock: TransportClock,
33	  config?: Partial<SchedulerConfig>,
34	  onTick?: (beatTime: number, beatNumber: number) => void,
35	  onAdvance?: (
36	    windowStart: number,
37	    windowEnd: number,
38	    timeOffset: number,
39	  ) => void,
40	): LookAheadScheduler {
41	  const intervalMs = config?.intervalMs ?? DEFAULT_CONFIG.intervalMs;
42	  const lookAheadSec =
43	    (config?.lookAheadMs ?? DEFAULT_CONFIG.lookAheadMs) / 1000;
44	
45	  let timerId: ReturnType<typeof setInterval> | null = null;
46	  let nextBeatTime = 0;
47	  let currentBeat = 0;
48	
49	  function syncToPosition(cursorSec: number): void {
50	    const spb = clock.getTempoMap().secondsPerBeat();
51	    const totalBeats = cursorSec / spb;
52	    const wholeBeat = Math.floor(totalBeats + 1e-9);
53	    const remainder = totalBeats - wholeBeat;
54	
55	    if (remainder < 1e-6) {
56	      // On a beat boundary — schedule this beat now
57	      currentBeat = wholeBeat;
58	      nextBeatTime = ctx.currentTime;
59	    } else {
60	      // Between beats — schedule next beat
61	      currentBeat = wholeBeat + 1;
62	      nextBeatTime = ctx.currentTime + (currentBeat * spb - cursorSec);
63	    }
64	  }
65	
66	  function advance(): void {
67	    if (clock.state !== "playing") return;
68	
69	    // Drive SAB cursor updates and detect loop wraps
70	    clock.updateCursor();
71	
72	    if (clock.didLoopWrap()) {
73	      syncToPosition(clock.getCursorSeconds());
74	    }
75	
76	    const scheduleUntil = ctx.currentTime + lookAheadSec;
77	    const spb = clock.getTempoMap().secondsPerBeat();
78	
79	    // Constrain scheduling window to the loop end boundary
80	    const loop = clock.getLoop();
81	    let effectiveUntil = scheduleUntil;
82	    if (loop.enabled && loop.end > loop.start) {
83	      const cursorNow = clock.getCursorSeconds();
84	      const timeToLoopEnd = loop.end - cursorNow;
85	      if (timeToLoopEnd > 0) {
86	        effectiveUntil = Math.min(
87	          scheduleUntil,
88	          ctx.currentTime + timeToLoopEnd,
89	        );
90	      }
91	    }
92	
93	    // Fire window-level callback for continuous schedulers (automation, clips)
94	    const timeOffset = ctx.currentTime - clock.getCursorSeconds();
95	    onAdvance?.(ctx.currentTime, effectiveUntil, timeOffset);
96	
97	    while (nextBeatTime < effectiveUntil) {
98	      onTick?.(nextBeatTime, currentBeat);
99	      currentBeat++;
100	      nextBeatTime += spb;
101	    }
102	  }
103	
104	  const scheduler: LookAheadScheduler = {
105	    get isRunning(): boolean {
106	      return timerId !== null;
107	    },
108	
109	    start(): void {
110	      if (timerId !== null) return;
111	
112	      // Phase-correct: sync beat position to current cursor
113	      syncToPosition(clock.getCursorSeconds());
114	
115	      timerId = setInterval(advance, intervalMs);
116	      advance();
117	    },
118	
119	    stop(): void {
120	      if (timerId !== null) {
121	        clearInterval(timerId);
122	        timerId = null;
123	      }
124	      nextBeatTime = 0;
125	      currentBeat = 0;
126	    },
127	
128	    sync(): void {
129	      syncToPosition(clock.getCursorSeconds());
130	    },
131	  };
132	
133	  return scheduler;
134	}
