/**
 * LFO (Low Frequency Oscillator) for modulation.
 * Supports sine, square, triangle, and sample-and-hold shapes.
 * Output range: [-1, 1], scaled by depth at the modulation destination.
 */

export type LFOShape = "sine" | "square" | "triangle" | "sample-and-hold";

/**
 * Stateful LFO. Call `process()` once per sample.
 * Zero-allocation in the hot path.
 */
export type LFO = {
  shape: LFOShape;
  /** Advance one sample. Returns output in [-1, 1]. */
  process(rate: number, sampleRate: number): number;
  /** Reset phase. */
  reset(): void;
};

/** Deterministic xorshift32 PRNG (zero-allocation, no Math.random). */
function xorshift32(seed: number): number {
  let x = seed;
  x ^= x << 13;
  x ^= x >>> 17;
  x ^= x << 5;
  return x;
}

export function createLFO(shape: LFOShape = "sine"): LFO {
  let phase = 0;
  let shValue = 0; // Sample-and-hold current value
  let prevPhase = 0; // For detecting S&H trigger
  let prngState = 123456789; // PRNG seed

  const lfo: LFO = {
    shape,

    process(rate: number, sampleRate: number): number {
      const dt = rate / sampleRate;
      let out: number;

      switch (lfo.shape) {
        case "sine":
          out = Math.sin(2 * Math.PI * phase);
          break;

        case "square":
          out = phase < 0.5 ? 1 : -1;
          break;

        case "triangle":
          // Ramp 0->1->0 mapped to -1->1->-1
          out = phase < 0.5 ? 4 * phase - 1 : 3 - 4 * phase;
          break;

        case "sample-and-hold":
          // New deterministic pseudo-random value each cycle
          if (phase < prevPhase) {
            prngState = xorshift32(prngState);
            // Map signed int32 to [-1, 1) via division by 2^31
            shValue = prngState / 2147483648;
          }
          out = shValue;
          break;

        default:
          out = 0;
      }

      prevPhase = phase;
      phase += dt;
      if (phase >= 1) phase -= 1;

      return out;
    },

    reset(): void {
      phase = 0;
      prevPhase = 0;
      shValue = 0;
      prngState = 123456789;
    },
  };

  return lfo;
}

/**
 * Shared types for the synthesizer engine.
 * Used by both the AudioWorklet processor and main thread.
 *
 * Exports: SynthParameterMap, SynthVoiceCommand (as specified by epic).
 */

import type { WaveformType } from "./dsp/polyblep";
import type { FilterType } from "./dsp/biquad-coeffs";
import type { LFOShape } from "./dsp/lfo";

// ─── Voice Commands (main thread → worklet) ───

export type SynthVoiceCommand =
  | { type: "noteOn"; note: number; velocity: number; legato: boolean }
  | { type: "noteOff"; note: number }
  | { type: "allNotesOff" }
  | { type: "setParam"; key: string; value: number }
  | {
      type: "setModRoutes";
      routes: {
        sourceIdx: number;
        destIdx: number;
        amount: number;
        bipolar: boolean;
      }[];
    }
  | { type: "setModSource"; source: string; value: number };

// ─── Parameter Map ───

export type SynthParameterMap = {
  // Oscillator 1
  osc1Type: WaveformType;
  osc1Octave: number; // -2..+2
  osc1Detune: number; // cents, -100..+100
  osc1Level: number; // 0..1

  // Oscillator 2
  osc2Type: WaveformType;
  osc2Octave: number;
  osc2Detune: number;
  osc2Level: number;

  // Filter
  filterType: FilterType;
  filterCutoff: number; // Hz, 20..20000
  filterResonance: number; // Q, 0.5..20

  // Amplitude Envelope
  ampAttack: number; // seconds
  ampDecay: number;
  ampSustain: number; // 0..1
  ampRelease: number;

  // Filter Envelope
  filterAttack: number;
  filterDecay: number;
  filterSustain: number; // 0..1
  filterRelease: number;
  filterEnvDepth: number; // semitones, -60..+60

  // LFO 1
  lfo1Rate: number; // Hz, 0.1..20
  lfo1Depth: number; // 0..1
  lfo1Shape: LFOShape;

  // LFO 2
  lfo2Rate: number; // Hz, 0.1..20
  lfo2Depth: number; // 0..1
  lfo2Shape: LFOShape;

  // Glide
  glideTime: number; // seconds, 0..1

  // Master
  masterGain: number; // 0..1
};

/** Default parameter values */
export const DEFAULT_SYNTH_PARAMS: SynthParameterMap = {
  osc1Type: "saw",
  osc1Octave: 0,
  osc1Detune: 0,
  osc1Level: 0.8,

  osc2Type: "saw",
  osc2Octave: 0,
  osc2Detune: 7, // Slight detune for thickness
  osc2Level: 0.5,

  filterType: "lowpass",
  filterCutoff: 5000,
  filterResonance: 1,

  ampAttack: 0.01,
  ampDecay: 0.2,
  ampSustain: 0.7,
  ampRelease: 0.3,

  filterAttack: 0.01,
  filterDecay: 0.3,
  filterSustain: 0.3,
  filterRelease: 0.5,
  filterEnvDepth: 24,

  lfo1Rate: 5,
  lfo1Depth: 0,
  lfo1Shape: "sine",

  lfo2Rate: 3,
  lfo2Depth: 0,
  lfo2Shape: "sine",

  glideTime: 0,

  masterGain: 0.7,
};

// ─── MIDI → Frequency Conversion ───

/** Convert MIDI note number to frequency in Hz. A4 = 69 = 440Hz. */
export function midiToFreq(note: number): number {
  return 440 * Math.pow(2, (note - 69) / 12);
}

/** Waveform type index mapping for AudioParam/message passing */
export const WAVEFORM_TYPES: readonly WaveformType[] = [
  "sine",
