      makeTrack({ clipIds: ["clip-1"], solo: true }),
      makeTrack({ id: "track-2", clipIds: ["clip-2"] }),
    ];

    const bounds = computeSessionBounds(tracks, clips);
    expect(bounds.end).toBe(5); // Only soloed track
  });
});

// ─── buildEventTimeline ───

describe("buildEventTimeline", () => {
  it("collects audio clips for non-muted tracks", () => {
    const clips = {
      "clip-1": makeAudioClip(),
    };
    const tracks = [makeTrack()];
    const timeline = buildEventTimeline(tracks, clips);

    expect(timeline.audioClips.length).toBe(1);
    expect(timeline.audioClips[0]?.clip.id).toBe("clip-1");
  });

  it("excludes clips from muted tracks", () => {
    const clips = {
      "clip-1": makeAudioClip(),
    };
    const tracks = [makeTrack({ muted: true })];
    const timeline = buildEventTimeline(tracks, clips);

    expect(timeline.audioClips.length).toBe(0);
  });

  it("collects MIDI clips separately", () => {
    const clips = {
      "midi-1": makeMidiClip({ id: "midi-1" }),
    };
    const tracks = [
      makeTrack({ id: "track-2", type: "instrument", clipIds: ["midi-1"] }),
    ];
    const timeline = buildEventTimeline(tracks, clips);

    expect(timeline.midiClips.length).toBe(1);
    expect(timeline.midiClips[0]?.clip.id).toBe("midi-1");
  });

  it("handles solo-in-place: only audible tracks included", () => {
    const clips = {
      "clip-1": makeAudioClip(),
      "clip-2": makeAudioClip({ id: "clip-2", trackId: "track-2" }),
    };
    const tracks = [
      makeTrack({ solo: true, clipIds: ["clip-1"] }),
      makeTrack({ id: "track-2", clipIds: ["clip-2"] }),
    ];
    const timeline = buildEventTimeline(tracks, clips);

    expect(timeline.audioClips.length).toBe(1);
    expect(timeline.audioClips[0]?.clip.trackId).toBe("track-1");
  });
});

// ─── BounceEngine (integration with mocks) ───

describe("createBounceEngine", () => {
  // Mock OfflineAudioContext
  function createMockOfflineAudioContext(duration: number, sampleRate: number) {
    const numSamples = Math.ceil(duration * sampleRate);
    const renderedBuffer = {
      numberOfChannels: 2,
      length: numSamples,
      sampleRate,
      duration,
      getChannelData(ch: number): Float32Array {
        // Return a simple sine wave for channel 0, silence for channel 1
        const data = new Float32Array(numSamples);
        if (ch === 0) {
          for (let i = 0; i < numSamples; i++) {
            data[i] = Math.sin((2 * Math.PI * 440 * i) / sampleRate) * 0.5;
          }
        }
        return data;
      },
    };

    const mockGainNode = () => ({
      gain: {
        value: 1,
        setValueAtTime: vi.fn(),
        linearRampToValueAtTime: vi.fn(),
        cancelScheduledValues: vi.fn(),
      },
      connect: vi.fn().mockReturnThis(),
      disconnect: vi.fn(),
    });

    const mockCompressor = () => ({
      threshold: { value: -1 },
      ratio: { value: 20 },
      knee: { value: 0 },
      attack: { value: 0.001 },
      release: { value: 0.01 },
      connect: vi.fn().mockReturnThis(),
      disconnect: vi.fn(),
    });

    const mockAnalyser = () => ({
      ...mockGainNode(),
      fftSize: 2048,
    });

    const mockPanner = () => ({
      pan: { value: 0 },
      connect: vi.fn().mockReturnThis(),
      disconnect: vi.fn(),
    });

    const mockSource = () => ({
      buffer: null as unknown,
      playbackRate: { value: 1, setValueAtTime: vi.fn() },
      connect: vi.fn().mockReturnThis(),
      disconnect: vi.fn(),
      start: vi.fn(),
      stop: vi.fn(),
      addEventListener: vi.fn(),
    });

    const mockFilter = () => ({
      type: "lowpass",
      frequency: { value: 350, setValueAtTime: vi.fn() },
      connect: vi.fn().mockReturnThis(),
      disconnect: vi.fn(),
    });

    const ctx = {
      sampleRate,
      length: numSamples,
      destination: { connect: vi.fn(), disconnect: vi.fn() },
      createGain: vi.fn().mockImplementation(mockGainNode),
      createAnalyser: vi.fn().mockImplementation(mockAnalyser),
      createStereoPanner: vi.fn().mockImplementation(mockPanner),
      createDynamicsCompressor: vi.fn().mockImplementation(mockCompressor),
      createBufferSource: vi.fn().mockImplementation(mockSource),
      createBiquadFilter: vi.fn().mockImplementation(mockFilter),
      createBuffer: vi.fn().mockImplementation((channels: number, length: number, sr: number) => ({
        numberOfChannels: channels,
        length,
        sampleRate: sr,
        getChannelData: () => new Float32Array(length),
        copyToChannel: vi.fn(),
      })),
      startRendering: vi.fn().mockResolvedValue(renderedBuffer),
      suspend: vi.fn().mockResolvedValue(undefined),
      resume: vi.fn(),
    };

    return ctx;
  }

  it("yields progress updates during bounce", async () => {
    const clips = { "clip-1": makeAudioClip({ duration: 2 }) };
    const tracks = [makeTrack()];
    const mockBuffer = {
      numberOfChannels: 1,
      length: 44100,
      sampleRate: 44100,
      getChannelData: () => new Float32Array(44100),
    };

    const options: BounceOptions = {
      sampleRate: 44100,
      bitDepth: 16,
      range: { type: "full" },
      tracks,
      clips,
      automationLanes: [],
      masterLevel: 1,
      getBuffer: () => mockBuffer as unknown as AudioBuffer,
      instruments: new Map(),
    };

    const engine = createBounceEngine(
      (dur, sr) => createMockOfflineAudioContext(dur, sr) as unknown as OfflineAudioContext,
    );

    const progress: string[] = [];
    const gen = engine.bounce(options);

    let result;
    for (;;) {
      const next = await gen.next();
      if (next.done) {
        result = next.value;
        break;
      }
      progress.push(next.value.phase);
    }

    expect(progress).toContain("preparing");
    expect(progress).toContain("encoding");
    expect(result).toBeDefined();
    expect(result.blob).toBeDefined();
    expect(result.blob.type).toBe("audio/wav");
  });

  it("respects region range selection", async () => {
    const clips = {
      "clip-1": makeAudioClip({ startTime: 0, duration: 10 }),
    };
    const tracks = [makeTrack()];
    const mockBuffer = {
      numberOfChannels: 1,
      length: 44100,
      sampleRate: 44100,
      getChannelData: () => new Float32Array(44100),
    };

    const options: BounceOptions = {
      sampleRate: 44100,
      bitDepth: 16,
      range: { type: "region", start: 2, end: 5 },
      tracks,
      clips,
      automationLanes: [],
      masterLevel: 1,
      getBuffer: () => mockBuffer as unknown as AudioBuffer,
      instruments: new Map(),
    };

    const engine = createBounceEngine(
      (dur, sr) => createMockOfflineAudioContext(dur, sr) as unknown as OfflineAudioContext,
    );

    const gen = engine.bounce(options);
    let result;
    for (;;) {
      const next = await gen.next();
      if (next.done) {
        result = next.value;
        break;
      }
    }

    // Duration should be 3 seconds (5 - 2)
    expect(result.duration).toBe(3);
  });

  it("can be cancelled", async () => {
    const clips = { "clip-1": makeAudioClip({ duration: 60 }) };
    const tracks = [makeTrack()];
    const mockBuffer = {
      numberOfChannels: 1,
      length: 44100,
      sampleRate: 44100,
      getChannelData: () => new Float32Array(44100),
    };

    const options: BounceOptions = {
      sampleRate: 44100,
      bitDepth: 16,
      range: { type: "full" },
      tracks,
      clips,
      automationLanes: [],
      masterLevel: 1,
      getBuffer: () => mockBuffer as unknown as AudioBuffer,
      instruments: new Map(),
    };

    const engine = createBounceEngine(
      (dur, sr) => createMockOfflineAudioContext(dur, sr) as unknown as OfflineAudioContext,
    );

    // Cancel immediately
    engine.cancel();

    const gen = engine.bounce(options);
    const first = await gen.next();

    // Should terminate quickly due to cancellation
    expect(first.done).toBe(true);
  });
});

