it("can be cancelled", async () => {
  const clips = { "clip-1": makeAudioClip({ duration: 60 }) };
  const tracks = [makeTrack()];
  const mockBuffer = {
    numberOfChannels: 1,
    length: 44100,
    sampleRate: 44100,
    getChannelData: () => new Float32Array(44100),
  };

  const options: BounceOptions = {
    sampleRate: 44100,
    bitDepth: 16,
    range: { type: "full" },
    tracks,
    clips,
    automationLanes: [],
    masterLevel: 1,
    getBuffer: () => mockBuffer as unknown as AudioBuffer,
    instruments: new Map(),
  };

  const engine = createBounceEngine(
    (dur, sr) => createMockOfflineAudioContext(dur, sr) as unknown as OfflineAudioContext,
  );

  // Cancel immediately
  engine.cancel();

  const gen = engine.bounce(options);
  const first = await gen.next();

  // Should terminate quickly due to cancellation
  expect(first.done).toBe(true);
});

