10	import type { AutomationLane } from "@audio/automation/automation-types";
11	import type { DrumInstrumentId, DrumInstrumentParams } from "@audio/drum-machine/drum-types";
12	import type { SynthParameterMap } from "@audio/synth/synth-types";
