14	/** Bounce range: either full session or a specific time region */
15	export type BounceRange =
16	  | { readonly type: "full" }
17	  | { readonly type: "region"; readonly start: number; readonly end: number };
18	
19	/** Per-track instrument configuration for offline rendering */
20	export type TrackInstrumentConfig =
21	  | { readonly type: "audio" }
22	  | {
23	      readonly type: "synth";
24	      readonly params: SynthParameterMap;
25	    }
26	  | {
27	      readonly type: "drums";
28	      readonly samples: ReadonlyMap<DrumInstrumentId, AudioBuffer>;
29	      readonly params: ReadonlyMap<DrumInstrumentId, DrumInstrumentParams>;
30	    };
31	
32	/** Options for a bounce operation */
33	export type BounceOptions = {
34	  readonly sampleRate: number;
35	  readonly bitDepth: 16 | 24 | 32;
36	  readonly range: BounceRange;
37	  readonly tracks: readonly TrackModel[];
38	  readonly clips: Readonly<Record<string, AudioClipModel | MidiClipModel>>;
39	  readonly automationLanes: readonly AutomationLane[];
40	  readonly masterLevel: number;
41	  readonly getBuffer: (sourceId: string) => AudioBuffer | undefined;
42	  readonly instruments: ReadonlyMap<string, TrackInstrumentConfig>;
43	};
44	
45	/** Progress update during bounce */
46	export type BounceProgress = {
47	  readonly phase: "preparing" | "rendering" | "encoding" | "complete";
48	  readonly progress: number; // 0..1
49	  readonly renderedSeconds: number;
50	  readonly totalSeconds: number;
51	};
52	
53	/** Result of a successful bounce */
54	export type BounceResult = {
55	  readonly blob: Blob;
56	  readonly duration: number;
57	  readonly sampleRate: number;
58	  readonly channels: number;
59	};
60	
61	/** Bounce engine interface */
62	export type BounceEngine = {
63	  /** Start a bounce operation. Returns async iterable of progress updates. */
64	  bounce(options: BounceOptions): AsyncGenerator<BounceProgress, BounceResult>;
65	  /** Cancel the current bounce operation. */
