1	/**
2	 * WAV file encoder with incremental chunk support.
3	 * Supports 16-bit PCM, 24-bit PCM, and 32-bit IEEE float.
4	 *
5	 * Two modes:
6	 * 1. Single-pass: encodeWav() for small files
7	 * 2. Chunked: encodeWavHeader() + encodePcmChunk()* + assembleWav()
8	 */
9	
10	function clamp(v: number, min: number, max: number): number {
11	  return Math.min(max, Math.max(min, v));
12	}
13	
14	function writeString(view: DataView, offset: number, str: string): void {
15	  for (let i = 0; i < str.length; i++) {
16	    view.setUint8(offset + i, str.charCodeAt(i));
17	  }
18	}
19	
20	/**
21	 * Encode a WAV file header (44 bytes).
22	 * @param numChannels - Number of audio channels (1 = mono, 2 = stereo)
23	 * @param sampleRate - Sample rate in Hz
24	 * @param bitDepth - Bits per sample (16, 24, or 32)
25	 * @param totalSamples - Total number of sample frames (not total samples across all channels)
26	 */
27	export function encodeWavHeader(
28	  numChannels: number,
29	  sampleRate: number,
30	  bitDepth: 16 | 24 | 32,
31	  totalSamples: number,
32	): ArrayBuffer {
33	  const bytesPerSample = bitDepth / 8;
34	  const blockAlign = numChannels * bytesPerSample;
35	  const byteRate = sampleRate * blockAlign;
36	  const dataSize = totalSamples * blockAlign;
37	  const formatCode = bitDepth === 32 ? 3 : 1; // 3 = IEEE float, 1 = PCM
38	
39	  const buffer = new ArrayBuffer(44);
40	  const view = new DataView(buffer);
41	
42	  // RIFF header
43	  writeString(view, 0, "RIFF");
44	  view.setUint32(4, 36 + dataSize, true); // file size - 8
45	  writeString(view, 8, "WAVE");
46	
47	  // fmt sub-chunk
48	  writeString(view, 12, "fmt ");
49	  view.setUint32(16, 16, true); // sub-chunk size (16 for PCM)
50	  view.setUint16(20, formatCode, true);
51	  view.setUint16(22, numChannels, true);
52	  view.setUint32(24, sampleRate, true);
53	  view.setUint32(28, byteRate, true);
54	  view.setUint16(32, blockAlign, true);
55	  view.setUint16(34, bitDepth, true);
56	
57	  // data sub-chunk
58	  writeString(view, 36, "data");
59	  view.setUint32(40, dataSize, true);
60	
61	  return buffer;
62	}
63	
64	/**
65	 * Encode a chunk of interleaved PCM data from channel arrays.
66	 * @param channels - Array of Float32Arrays, one per channel
67	 * @param bitDepth - Bits per sample (16, 24, or 32)
68	 */
69	export function encodePcmChunk(
70	  channels: readonly Float32Array[],
71	  bitDepth: 16 | 24 | 32,
72	): ArrayBuffer {
73	  const numChannels = channels.length;
74	  const firstChannel = channels[0];
75	  if (!firstChannel || numChannels === 0) return new ArrayBuffer(0);
76	
77	  const numSamples = firstChannel.length;
78	  const bytesPerSample = bitDepth / 8;
79	  const buffer = new ArrayBuffer(numSamples * numChannels * bytesPerSample);
80	
81	  if (bitDepth === 16) {
82	    const view = new DataView(buffer);
83	    let offset = 0;
84	    for (let s = 0; s < numSamples; s++) {
85	      for (let c = 0; c < numChannels; c++) {
86	        const ch = channels[c];
87	        const sample = ch ? clamp(ch[s] ?? 0, -1, 1) : 0;
88	        const int16 = Math.round(sample < 0 ? sample * 32768 : sample * 32767);
89	        view.setInt16(offset, int16, true);
90	        offset += 2;
91	      }
92	    }
93	  } else if (bitDepth === 24) {
94	    const bytes = new Uint8Array(buffer);
95	    let offset = 0;
96	    for (let s = 0; s < numSamples; s++) {
97	      for (let c = 0; c < numChannels; c++) {
98	        const ch = channels[c];
99	        const sample = ch ? clamp(ch[s] ?? 0, -1, 1) : 0;
100	        const int24 = Math.round(
101	          sample < 0 ? sample * 8388608 : sample * 8388607,
102	        );
103	        bytes[offset++] = int24 & 0xff;
104	        bytes[offset++] = (int24 >> 8) & 0xff;
105	        bytes[offset++] = (int24 >> 16) & 0xff;
106	      }
107	    }
108	  } else {
109	    // 32-bit float
110	    const view = new DataView(buffer);
111	    let offset = 0;
112	    for (let s = 0; s < numSamples; s++) {
113	      for (let c = 0; c < numChannels; c++) {
114	        const ch = channels[c];
115	        view.setFloat32(offset, ch?.[s] ?? 0, true);
116	        offset += 4;
117	      }
118	    }
119	  }
120	
121	  return buffer;
122	}
123	
124	/**
125	 * Assemble a WAV file from a header and data chunks.
126	 */
127	export function assembleWav(
128	  header: ArrayBuffer,
129	  chunks: readonly ArrayBuffer[],
130	): Blob {
131	  return new Blob([header, ...chunks], { type: "audio/wav" });
132	}
133	
134	/**
135	 * Single-pass WAV encoding: header + all data in one call.
136	 * @param channels - Array of Float32Arrays, one per channel
137	 * @param sampleRate - Sample rate in Hz
138	 * @param bitDepth - Bits per sample (16, 24, or 32)
139	 */
140	export function encodeWav(
141	  channels: readonly Float32Array[],
142	  sampleRate: number,
143	  bitDepth: 16 | 24 | 32,
144	): Blob {
145	  const firstChannel = channels[0];
146	  const numSamples = firstChannel?.length ?? 0;
147	  const header = encodeWavHeader(channels.length, sampleRate, bitDepth, numSamples);
148	  const data = encodePcmChunk(channels, bitDepth);
149	  return assembleWav(header, [data]);
150	}
