1	/**
2	 * Offline synth renderer: renders MIDI note events to stereo audio
3	 * using the synth DSP functions directly (no AudioWorklet dependency).
4	 *
5	 * This mirrors the SynthProcessor logic but runs synchronously,
6	 * producing Float32Arrays suitable for use as AudioBufferSourceNodes
7	 * in the offline bounce context.
8	 */
9	
10	import type { MIDINoteEvent } from "@state/track/types";
11	import type { SynthParameterMap } from "@audio/synth/synth-types";
12	import { midiToFreq } from "@audio/synth/synth-types";
13	import { createPolyBLEPOsc } from "@audio/synth/dsp/polyblep";
14	import { createADSREnvelope, type ADSRParams } from "@audio/synth/dsp/adsr";
15	import {
16	  computeBiquadCoeffs,
17	  createBiquadFilter,
18	} from "@audio/synth/dsp/biquad-coeffs";
19	import { createLFO } from "@audio/synth/dsp/lfo";
20	
21	const MAX_VOICES = 16;
22	
23	type OfflineVoice = {
24	  active: boolean;
25	  releasing: boolean;
26	  note: number;
27	  osc1: ReturnType<typeof createPolyBLEPOsc>;
28	  osc2: ReturnType<typeof createPolyBLEPOsc>;
29	  ampEnv: ReturnType<typeof createADSREnvelope>;
30	  filterEnv: ReturnType<typeof createADSREnvelope>;
31	  filter: ReturnType<typeof createBiquadFilter>;
32	  targetFreq: number;
33	  currentFreq: number;
34	  velocity: number;
35	};
36	
37	function createOfflineVoice(): OfflineVoice {
38	  return {
39	    active: false,
40	    releasing: false,
41	    note: -1,
42	    osc1: createPolyBLEPOsc("saw"),
43	    osc2: createPolyBLEPOsc("saw"),
44	    ampEnv: createADSREnvelope(),
45	    filterEnv: createADSREnvelope(),
46	    filter: createBiquadFilter("lowpass"),
47	    targetFreq: 440,
48	    currentFreq: 440,
49	    velocity: 0,
50	  };
51	}
52	
53	type NoteEvent = {
54	  sample: number;
55	  type: "on" | "off";
56	  note: number;
57	  velocity: number;
58	};
59	
60	export type RenderedAudio = {
61	  readonly left: Float32Array;
62	  readonly right: Float32Array;
63	};
64	
65	/**
66	 * Render MIDI note events to stereo audio using synth DSP.
67	 * @param notes - MIDI note events (startTime relative to clip start)
68	 * @param duration - Total duration to render in seconds
69	 * @param sampleRate - Sample rate
70	 * @param params - Synth parameter snapshot
71	 */
72	export function renderMidiClipToAudio(
73	  notes: readonly MIDINoteEvent[],
74	  duration: number,
75	  sampleRate: number,
76	  params: SynthParameterMap,
77	): RenderedAudio {
78	  const totalSamples = Math.ceil(duration * sampleRate);
79	  const left = new Float32Array(totalSamples);
80	  const right = new Float32Array(totalSamples);
81	
82	  if (notes.length === 0) return { left, right };
83	
84	  // Build sorted event list (note-ons and note-offs)
85	  const events: NoteEvent[] = [];
86	  for (const note of notes) {
87	    const onSample = Math.floor(note.startTime * sampleRate);
88	    const offSample = Math.floor((note.startTime + note.duration) * sampleRate);
89	    events.push({ sample: onSample, type: "on", note: note.pitch, velocity: note.velocity });
90	    events.push({ sample: offSample, type: "off", note: note.pitch, velocity: 0 });
91	  }
92	  events.sort((a, b) => a.sample - b.sample || (a.type === "off" ? -1 : 1));
93	
94	  // Pre-allocate voices
95	  const voices: OfflineVoice[] = Array.from({ length: MAX_VOICES }, () =>
96	    createOfflineVoice(),
97	  );
98	
99	  // LFOs (shared across all voices)
100	  const lfo1 = createLFO(params.lfo1Shape);
101	  const lfo2 = createLFO(params.lfo2Shape);
102	
103	  // ADSR params (pre-allocated)
104	  const ampParams: ADSRParams = {
105	    attack: params.ampAttack,
106	    decay: params.ampDecay,
107	    sustain: params.ampSustain,
108	    release: params.ampRelease,
109	  };
110	  const filterParams: ADSRParams = {
111	    attack: params.filterAttack,
112	    decay: params.filterDecay,
113	    sustain: params.filterSustain,
114	    release: params.filterRelease,
115	  };
116	
117	  // Pre-compute constants
118	  const osc1OctMul = Math.pow(2, params.osc1Octave);
119	  const osc1DetMul = Math.pow(2, params.osc1Detune / 1200);
120	  const osc2OctMul = Math.pow(2, params.osc2Octave);
121	  const osc2DetMul = Math.pow(2, params.osc2Detune / 1200);
122	
123	  let eventIdx = 0;
124	
125	  for (let s = 0; s < totalSamples; s++) {
126	    // Process events at this sample
127	    while (eventIdx < events.length) {
128	      const evt = events[eventIdx];
129	      if (!evt || evt.sample > s) break;
130	
131	      if (evt.type === "on") {
132	        allocateNoteOn(voices, evt.note, evt.velocity, params);
133	      } else {
134	        releaseNote(voices, evt.note);
135	      }
136	      eventIdx++;
137	    }
138	
139	    // LFO processing
140	    const lfo1Val = lfo1.process(params.lfo1Rate, sampleRate) * params.lfo1Depth;
141	    const lfo2Val = lfo2.process(params.lfo2Rate, sampleRate) * params.lfo2Depth;
142	    // Unused but kept for parity with processor — lfo modulation can be added later
143	    void lfo1Val;
144	    void lfo2Val;
145	
146	    let mixL = 0;
147	    let mixR = 0;
148	
149	    for (let vi = 0; vi < MAX_VOICES; vi++) {
150	      const v = voices[vi];
151	      if (!v || !v.active) continue;
152	
153	      // Check if release finished
154	      if (v.ampEnv.stage === "idle" && v.releasing) {
155	        v.active = false;
156	        v.releasing = false;
157	        continue;
158	      }
159	
160	      // Pitch glide
161	      if (params.glideTime > 0 && v.currentFreq !== v.targetFreq) {
162	        const glideCoeff = 1 - Math.exp(-1 / (params.glideTime * sampleRate));
163	        v.currentFreq += glideCoeff * (v.targetFreq - v.currentFreq);
164	      } else {
165	        v.currentFreq = v.targetFreq;
166	      }
167	
168	      const baseFreq = v.currentFreq;
169	
170	      // Envelopes
171	      const filterEnvVal = v.filterEnv.process(filterParams, sampleRate);
172	      const ampLevel = v.ampEnv.process(ampParams, sampleRate);
173	
174	      // Oscillators
175	      const freq1 = baseFreq * osc1OctMul * osc1DetMul;
176	      const freq2 = baseFreq * osc2OctMul * osc2DetMul;
177	      const osc1Out = v.osc1.next(freq1, sampleRate) * params.osc1Level;
178	      const osc2Out = v.osc2.next(freq2, sampleRate) * params.osc2Level;
179	      let sample = osc1Out + osc2Out;
180	
181	      // Filter (recompute coefficients periodically for efficiency)
182	      if (s % 128 === 0) {
183	        const cutoffModSt = filterEnvVal * params.filterEnvDepth;
184	        const modulatedCutoff = params.filterCutoff * Math.pow(2, cutoffModSt / 12);
185	        const clampedCutoff = Math.min(Math.max(modulatedCutoff, 20), sampleRate / 2 - 100);
186	        computeBiquadCoeffs(
187	          params.filterType,
188	          clampedCutoff,
189	          params.filterResonance,
190	          sampleRate,
191	          v.filter.coeffs,
192	        );
193	      }
194	
195	      sample = v.filter.process(sample);
196	
197	      // Velocity -> amplitude
198	      const velAmp = 0.5 + v.velocity * 0.5;
199	      sample *= ampLevel * velAmp * params.masterGain;
200	
201	      // Clamp to prevent overflow
202	      if (!isFinite(sample)) sample = 0;
203	
204	      mixL += sample;
205	      mixR += sample;
206	    }
207	
208	    left[s] = mixL;
209	    right[s] = mixR;
210	  }
211	
212	  return { left, right };
213	}
214	
215	/** Allocate a voice for a new note (oldest-steal if full) */
216	function allocateNoteOn(
217	  voices: OfflineVoice[],
218	  note: number,
219	  velocity: number,
220	  params: SynthParameterMap,
221	): void {
222	  // Find free voice
223	  let idx = -1;
224	  for (let i = 0; i < MAX_VOICES; i++) {
225	    if (!voices[i]?.active) {
226	      idx = i;
227	      break;
228	    }
229	  }
230	
231	  // Steal oldest releasing voice if no free voice
232	  if (idx === -1) {
233	    for (let i = 0; i < MAX_VOICES; i++) {
234	      if (voices[i]?.releasing) {
235	        idx = i;
236	        break;
237	      }
238	    }
239	  }
240	
241	  // Steal first voice as last resort
242	  if (idx === -1) idx = 0;
243	
244	  const v = voices[idx];
245	  if (!v) return;
246	
247	  const freq = midiToFreq(note);
248	  v.active = true;
249	  v.releasing = false;
250	  v.note = note;
251	  v.velocity = velocity / 127;
252	  v.targetFreq = freq;
253	  v.currentFreq = freq;
254	
255	  v.osc1.reset();
256	  v.osc2.reset();
257	  v.filter.reset();
258	  v.osc1.type = params.osc1Type;
259	  v.osc2.type = params.osc2Type;
260	  v.filter.type = params.filterType;
261	  v.ampEnv.gate(false);
262	  v.filterEnv.gate(false);
263	}
264	
265	/** Release all voices playing this note */
266	function releaseNote(voices: OfflineVoice[], note: number): void {
267	  for (let i = 0; i < MAX_VOICES; i++) {
268	    const v = voices[i];
269	    if (v && v.active && !v.releasing && v.note === note) {
270	      v.releasing = true;
271	      v.ampEnv.release();
272	      v.filterEnv.release();
273	    }
274	  }
275	}
