1	/**
2	 * Bounce/export engine: offline rendering of the session to WAV.
3	 *
4	 * Renders the full audio graph in an OfflineAudioContext:
5	 * - Mixer channel strips + master bus + brickwall limiter
6	 * - Audio clip scheduling
7	 * - Pre-rendered synth MIDI clips
8	 * - Drum machine triggers
9	 * - Automation curves
10	 *
11	 * Cooperative cancellation via internal flag.
12	 * Progress reporting via async generator.
13	 *
14	 * EARS: R-EVT-14, NFR-17
15	 */
16	
17	import type {
18	  AudioClipModel,
19	  MidiClipModel,
20	  TrackModel,
21	  ClipModel,
22	} from "@state/track/types";
23	import { isAudioClip, isMidiClip } from "@state/track/types";
24	import type {
25	  BounceEngine,
26	  BounceOptions,
27	  BounceProgress,
28	  BounceResult,
29	  TrackInstrumentConfig,
30	} from "./types";
31	import type { AutomationLane } from "@audio/automation/automation-types";
32	import {
33	  evaluateCurve,
34	  denormalize,
35	  findPointsInRange,
36	} from "@audio/automation/automation-curve";
37	import { renderMidiClipToAudio } from "./synth-renderer";
38	import { encodeWavHeader, encodePcmChunk, assembleWav } from "./wav-encoder";
39	
40	// ─── Session analysis (exported for testing) ───
41	
42	export type SessionBounds = {
43	  readonly start: number;
44	  readonly end: number;
45	};
46	
47	/** Determine which tracks are audible given mute/solo state */
48	function getAudibleTrackIds(tracks: readonly TrackModel[]): Set<string> {
49	  const hasSolo = tracks.some((t) => t.solo);
50	  const audible = new Set<string>();
51	
52	  for (const track of tracks) {
53	    if (track.muted) continue;
54	    if (hasSolo && !track.solo && !track.soloIsolate) continue;
55	    audible.add(track.id);
56	  }
57	
58	  return audible;
59	}
60	
61	/** Compute the time bounds of all audible clips in the session */
62	export function computeSessionBounds(
63	  tracks: readonly TrackModel[],
64	  clips: Readonly<Record<string, ClipModel>>,
65	): SessionBounds {
66	  const audible = getAudibleTrackIds(tracks);
67	  let start = Infinity;
68	  let end = 0;
69	
70	  for (const track of tracks) {
71	    if (!audible.has(track.id)) continue;
72	    for (const clipId of track.clipIds) {
73	      const clip = clips[clipId];
74	      if (!clip) continue;
75	      start = Math.min(start, clip.startTime);
76	      end = Math.max(end, clip.startTime + clip.duration);
77	    }
78	  }
79	
80	  if (start === Infinity) start = 0;
81	  return { start, end };
82	}
83	
84	// ─── Event timeline (exported for testing) ───
85	
86	export type TimelineAudioClip = {
87	  readonly clip: AudioClipModel;
88	  readonly trackId: string;
89	};
90	
91	export type TimelineMidiClip = {
92	  readonly clip: MidiClipModel;
93	  readonly trackId: string;
94	};
95	
96	export type EventTimeline = {
97	  readonly audioClips: readonly TimelineAudioClip[];
98	  readonly midiClips: readonly TimelineMidiClip[];
99	};
100	
101	/** Build a timeline of events for audible tracks */
102	export function buildEventTimeline(
103	  tracks: readonly TrackModel[],
104	  clips: Readonly<Record<string, ClipModel>>,
105	): EventTimeline {
106	  const audible = getAudibleTrackIds(tracks);
107	  const audioClips: TimelineAudioClip[] = [];
108	  const midiClips: TimelineMidiClip[] = [];
109	
110	  for (const track of tracks) {
111	    if (!audible.has(track.id)) continue;
112	    for (const clipId of track.clipIds) {
113	      const clip = clips[clipId];
114	      if (!clip) continue;
115	      if (isAudioClip(clip)) {
116	        audioClips.push({ clip, trackId: track.id });
117	      } else if (isMidiClip(clip)) {
118	        midiClips.push({ clip, trackId: track.id });
119	      }
120	    }
121	  }
122	
123	  return { audioClips, midiClips };
124	}
