126	// ─── Offline mixer graph ───
127	
128	type OfflineMixerStrip = {
129	  inputGain: GainNode;
130	  faderGain: GainNode;
131	  panner: StereoPannerNode;
132	  muteGain: GainNode;
133	};
134	
135	type OfflineMixer = {
136	  strips: Map<string, OfflineMixerStrip>;
137	  masterInput: GainNode;
138	  masterFader: GainNode;
139	  limiter: DynamicsCompressorNode;
140	};
141	
142	function faderTaper(linear: number): number {
143	  if (linear <= 0) return 0;
144	  if (linear <= 1) return linear * linear;
145	  return 1 + (linear - 1);
146	}
147	
148	function buildOfflineMixer(
149	  ctx: OfflineAudioContext,
150	  tracks: readonly TrackModel[],
151	  masterLevel: number,
152	  audibleIds: Set<string>,
153	): OfflineMixer {
154	  // Master bus
155	  const masterInput = ctx.createGain();
156	  const masterFader = ctx.createGain();
157	  const limiter = ctx.createDynamicsCompressor();
158	
159	  // INV-2: Brickwall limiter
160	  limiter.threshold.value = -1;
161	  limiter.ratio.value = 20;
162	  limiter.knee.value = 0;
163	  limiter.attack.value = 0.001;
164	  limiter.release.value = 0.01;
165	
166	  masterInput.connect(masterFader);
167	  masterFader.connect(limiter);
168	  limiter.connect(ctx.destination);
169	  masterFader.gain.value = masterLevel;
170	
171	  // Channel strips
172	  const strips = new Map<string, OfflineMixerStrip>();
173	  for (const track of tracks) {
174	    if (!audibleIds.has(track.id)) continue;
175	
176	    const inputGain = ctx.createGain();
177	    const faderGain = ctx.createGain();
178	    const panner = ctx.createStereoPanner();
179	    const muteGain = ctx.createGain();
180	
181	    inputGain.connect(faderGain);
182	    faderGain.connect(panner);
183	    panner.connect(muteGain);
184	    muteGain.connect(masterInput);
185	
186	    faderGain.gain.value = faderTaper(track.volume);
187	    panner.pan.value = track.pan;
188	    muteGain.gain.value = 1; // Already filtered by audibleIds
189	
190	    strips.set(track.id, { inputGain, faderGain, panner, muteGain });
191	  }
192	
193	  return { strips, masterInput, masterFader, limiter };
194	}
195	
196	// ─── Audio clip scheduling ───
197	
198	function scheduleAudioClips(
199	  ctx: OfflineAudioContext,
200	  audioClips: readonly TimelineAudioClip[],
201	  mixer: OfflineMixer,
202	  rangeStart: number,
203	  getBuffer: (sourceId: string) => AudioBuffer | undefined,
204	): void {
205	  for (const { clip, trackId } of audioClips) {
206	    const strip = mixer.strips.get(trackId);
207	    if (!strip) continue;
208	
209	    const buffer = getBuffer(clip.sourceId);
210	    if (!buffer) continue;
211	
212	    // Compute timing relative to range start
213	    const clipStart = clip.startTime - rangeStart;
214	    const clipEnd = clipStart + clip.duration;
215	
216	    // Skip if clip is entirely before the render window
217	    if (clipEnd <= 0) continue;
218	
219	    const source = ctx.createBufferSource();
220	    source.buffer = buffer;
221	
222	    const gainNode = ctx.createGain();
223	    gainNode.gain.value = clip.gain;
224	
225	    // Apply fades
226	    const maxFadeIn = Math.min(clip.fadeIn, clip.duration);
227	    const maxFadeOut = Math.min(clip.fadeOut, clip.duration - maxFadeIn);
228	
229	    if (maxFadeIn > 0) {
230	      gainNode.gain.setValueAtTime(0, Math.max(0, clipStart));
231	      gainNode.gain.linearRampToValueAtTime(clip.gain, Math.max(0, clipStart) + maxFadeIn);
232	    }
233	    if (maxFadeOut > 0) {
234	      const fadeOutStart = clipEnd - maxFadeOut;
235	      gainNode.gain.setValueAtTime(clip.gain, Math.max(0, fadeOutStart));
236	      gainNode.gain.linearRampToValueAtTime(0, clipEnd);
237	    }
238	
239	    source.connect(gainNode);
240	    gainNode.connect(strip.inputGain);
241	
242	    // Handle clips that start before the render window
243	    const seekOffset = clipStart < 0 ? -clipStart : 0;
244	    const sourceOffset = clip.sourceOffset + seekOffset;
245	    const playDuration = clip.duration - seekOffset;
246	    const playStart = Math.max(0, clipStart);
247	
248	    source.start(playStart, sourceOffset, playDuration);
249	  }
250	}
251	
252	// ─── MIDI pre-rendering ───
253	
254	function scheduleMidiClips(
255	  ctx: OfflineAudioContext,
256	  midiClips: readonly TimelineMidiClip[],
257	  mixer: OfflineMixer,
258	  rangeStart: number,
259	  instruments: ReadonlyMap<string, TrackInstrumentConfig>,
260	): void {
261	  for (const { clip, trackId } of midiClips) {
262	    const strip = mixer.strips.get(trackId);
263	    if (!strip) continue;
264	
265	    const config = instruments.get(trackId);
266	    if (!config || config.type !== "synth") continue;
267	
268	    // Pre-render MIDI to audio using synth DSP
269	    const rendered = renderMidiClipToAudio(
270	      clip.noteEvents,
271	      clip.duration,
272	      ctx.sampleRate,
273	      config.params,
274	    );
275	
276	    // Create AudioBuffer from rendered data
277	    const audioBuffer = ctx.createBuffer(2, rendered.left.length, ctx.sampleRate);
278	    audioBuffer.copyToChannel(rendered.left, 0);
279	    audioBuffer.copyToChannel(rendered.right, 1);
280	
281	    // Schedule playback
282	    const clipStart = clip.startTime - rangeStart;
283	    if (clipStart + clip.duration <= 0) continue;
284	
285	    const source = ctx.createBufferSource();
286	    source.buffer = audioBuffer;
287	
288	    const seekOffset = clipStart < 0 ? -clipStart : 0;
289	    const playStart = Math.max(0, clipStart);
290	
291	    source.connect(strip.inputGain);
292	    source.start(playStart, seekOffset, clip.duration - seekOffset);
293	  }
294	}
295	
296	// ─── Drum scheduling ───
297	
298	function scheduleDrumClips(
299	  ctx: OfflineAudioContext,
300	  midiClips: readonly TimelineMidiClip[],
301	  mixer: OfflineMixer,
302	  rangeStart: number,
303	  instruments: ReadonlyMap<string, TrackInstrumentConfig>,
304	): void {
305	  for (const { clip, trackId } of midiClips) {
306	    const strip = mixer.strips.get(trackId);
307	    if (!strip) continue;
308	
309	    const config = instruments.get(trackId);
310	    if (!config || config.type !== "drums") continue;
311	
312	    // Schedule individual drum hits
313	    for (const note of clip.noteEvents) {
314	      const hitTime = clip.startTime + note.startTime - rangeStart;
315	      if (hitTime < 0) continue;
316	
317	      // Map MIDI pitch to drum instrument ID
318	      // Use a simplified mapping: we schedule the sample directly
319	      const drumId = mapPitchToDrum(note.pitch);
320	      if (!drumId) continue;
321	
322	      const sampleBuffer = config.samples.get(drumId);
323	      if (!sampleBuffer) continue;
324	
325	      const drumParams = config.params.get(drumId);
326	      const velocity = note.velocity / 127;
327	
328	      const source = ctx.createBufferSource();
329	      source.buffer = sampleBuffer;
330	      if (drumParams) {
331	        source.playbackRate.setValueAtTime(drumParams.tune, hitTime);
332	      }
333	
334	      const gain = ctx.createGain();
335	      const peakGain = Math.max(0.001, (drumParams?.volume ?? 1) * velocity);
336	      gain.gain.setValueAtTime(peakGain, hitTime);
337	      const decay = drumParams?.decay ?? 0.5;
338	      gain.gain.exponentialRampToValueAtTime(0.001, hitTime + decay);
339	
340	      source.connect(gain);
341	      gain.connect(strip.inputGain);
342	      source.start(hitTime);
343	      source.stop(hitTime + decay + 0.01);
344	    }
345	  }
346	}
347	
348	/** Simple MIDI pitch to drum ID mapping (GM drum map subset) */
349	function mapPitchToDrum(pitch: number): string | undefined {
350	  const map: Record<number, string> = {
351	    36: "bd", 35: "bd",
352	    38: "sd", 40: "sd",
353	    41: "lt", 43: "lt",
354	    45: "mt", 47: "mt",
355	    48: "ht", 50: "ht",
356	    37: "rs",
357	    39: "cp",
358	    56: "cb",
359	    46: "oh",
360	    42: "ch", 44: "ch",
361	    49: "cy", 51: "cy",
362	  };
363	  return map[pitch];
364	}
365	
366	// ─── Automation scheduling ───
367	
368	function scheduleAutomation(
369	  ctx: OfflineAudioContext,
370	  lanes: readonly AutomationLane[],
371	  mixer: OfflineMixer,
372	  rangeStart: number,
373	  duration: number,
374	): void {
375	  for (const lane of lanes) {
376	    if (!lane.armed || lane.mode === "write" || lane.points.length === 0) continue;
377	
378	    const strip = mixer.strips.get(lane.trackId);
379	    if (!strip) continue;
380	
381	    // Resolve target parameter
382	    const resolved = resolveOfflineParam(lane, strip);
383	    if (!resolved) continue;
384	
385	    const { param, range } = resolved;
386	
387	    // Schedule automation for the full render duration
388	    const startNorm = evaluateCurve(lane.points, rangeStart);
389	    const startVal = denormalize(startNorm, range);
390	    param.setValueAtTime(startVal, 0);
391	
392	    // Schedule breakpoints
393	    const innerPoints = findPointsInRange(lane.points, rangeStart, rangeStart + duration);
394	    for (const pt of innerPoints) {
395	      const ctxTime = pt.time - rangeStart;
396	      const val = denormalize(pt.value, range);
397	      param.linearRampToValueAtTime(val, ctxTime);
398	    }
399	
400	    // End value
401	    const endNorm = evaluateCurve(lane.points, rangeStart + duration);
402	    const endVal = denormalize(endNorm, range);
403	    param.linearRampToValueAtTime(endVal, duration);
404	  }
405	}
406	
407	type ResolvedOfflineParam = {
408	  param: AudioParam;
409	  range: { min: number; max: number };
410	};
411	
412	function resolveOfflineParam(
413	  lane: AutomationLane,
414	  strip: OfflineMixerStrip,
415	): ResolvedOfflineParam | undefined {
416	  if (lane.target.type === "mixer") {
417	    if (lane.target.param === "volume") {
418	      return { param: strip.faderGain.gain, range: { min: 0, max: 2 } };
419	    }
420	    if (lane.target.param === "pan") {
421	      return { param: strip.panner.pan, range: { min: -1, max: 1 } };
422	    }
423	  }
424	  // Effect and synth automation not supported in offline render v1
425	  return undefined;
426	}
427	
428	// ─── WAV encoding (chunked) ───
429	
430	const WAV_CHUNK_SAMPLES = 30 * 44100; // ~30 seconds per encoding chunk
431	
432	function encodeRenderedBuffer(
433	  buffer: AudioBuffer,
434	  bitDepth: 16 | 24 | 32,
435	): Blob {
436	  const numChannels = Math.min(buffer.numberOfChannels, 2);
437	  const totalSamples = buffer.length;
438	  const sampleRate = buffer.sampleRate;
439	
440	  const channelData: Float32Array[] = [];
441	  for (let c = 0; c < numChannels; c++) {
442	    channelData.push(buffer.getChannelData(c));
443	  }
444	
445	  const header = encodeWavHeader(numChannels, sampleRate, bitDepth, totalSamples);
446	  const chunks: ArrayBuffer[] = [];
447	
448	  // Encode in chunks for memory efficiency
449	  for (let offset = 0; offset < totalSamples; offset += WAV_CHUNK_SAMPLES) {
450	    const end = Math.min(offset + WAV_CHUNK_SAMPLES, totalSamples);
451	    const chunkChannels = channelData.map((ch) => ch.subarray(offset, end));
452	    chunks.push(encodePcmChunk(chunkChannels, bitDepth));
453	  }
454	
455	  return assembleWav(header, chunks);
456	}
457	
458	// ─── BounceEngine factory ───
459	
460	type OfflineContextFactory = (
461	  duration: number,
462	  sampleRate: number,
463	) => OfflineAudioContext;
464	
465	const defaultContextFactory: OfflineContextFactory = (duration, sampleRate) => {
466	  const length = Math.ceil(duration * sampleRate);
467	  return new OfflineAudioContext(2, length, sampleRate);
468	};
469	
470	export function createBounceEngine(
471	  contextFactory: OfflineContextFactory = defaultContextFactory,
472	): BounceEngine {
473	  let cancelled = false;
474	
475	  return {
476	    async *bounce(options: BounceOptions): AsyncGenerator<BounceProgress, BounceResult> {
477	      cancelled = false;
478	
479	      // Check cancellation early
480	      if (cancelled) {
481	        return { blob: new Blob(), duration: 0, sampleRate: options.sampleRate, channels: 2 };
482	      }
483	
484	      // Phase: Preparing
485	      yield {
486	        phase: "preparing",
487	        progress: 0,
488	        renderedSeconds: 0,
489	        totalSeconds: 0,
490	      };
491	
492	      // Determine render range
493	      const sessionBounds = computeSessionBounds(options.tracks, options.clips);
494	      let rangeStart: number;
495	      let rangeEnd: number;
496	
497	      if (options.range.type === "region") {
498	        rangeStart = options.range.start;
499	        rangeEnd = options.range.end;
500	      } else {
501	        rangeStart = sessionBounds.start;
502	        rangeEnd = sessionBounds.end;
503	      }
504	
505	      const duration = Math.max(0, rangeEnd - rangeStart);
506	      if (duration === 0 || cancelled) {
507	        return {
508	          blob: new Blob(),
509	          duration: 0,
510	          sampleRate: options.sampleRate,
511	          channels: 2,
512	        };
513	      }
514	
515	      // Build event timeline
516	      const timeline = buildEventTimeline(options.tracks, options.clips);
517	      const audibleIds = getAudibleTrackIds(options.tracks);
518	
519	      if (cancelled) {
520	        return { blob: new Blob(), duration: 0, sampleRate: options.sampleRate, channels: 2 };
521	      }
522	
523	      // Phase: Rendering
524	      yield {
525	        phase: "rendering",
526	        progress: 0.1,
527	        renderedSeconds: 0,
528	        totalSeconds: duration,
529	      };
530	
531	      // Create OfflineAudioContext
532	      const ctx = contextFactory(duration, options.sampleRate);
533	
534	      // Build offline mixer graph
535	      const mixer = buildOfflineMixer(ctx, options.tracks, options.masterLevel, audibleIds);
536	
537	      // Schedule audio clips
538	      scheduleAudioClips(ctx, timeline.audioClips, mixer, rangeStart, options.getBuffer);
539	
540	      // Schedule MIDI clips (pre-rendered synth)
541	      scheduleMidiClips(ctx, timeline.midiClips, mixer, rangeStart, options.instruments);
542	
543	      // Schedule drum clips
544	      scheduleDrumClips(ctx, timeline.midiClips, mixer, rangeStart, options.instruments);
545	
546	      // Schedule automation
547	      scheduleAutomation(ctx, options.automationLanes, mixer, rangeStart, duration);
548	
549	      if (cancelled) {
550	        return { blob: new Blob(), duration: 0, sampleRate: options.sampleRate, channels: 2 };
551	      }
552	
553	      // Render
554	      const renderedBuffer = await ctx.startRendering();
555	
556	      yield {
557	        phase: "rendering",
558	        progress: 0.7,
559	        renderedSeconds: duration,
560	        totalSeconds: duration,
561	      };
562	
563	      if (cancelled) {
564	        return { blob: new Blob(), duration: 0, sampleRate: options.sampleRate, channels: 2 };
565	      }
566	
567	      // Phase: Encoding
568	      yield {
569	        phase: "encoding",
570	        progress: 0.8,
571	        renderedSeconds: duration,
572	        totalSeconds: duration,
573	      };
574	
575	      const blob = encodeRenderedBuffer(renderedBuffer, options.bitDepth);
576	
577	      yield {
578	        phase: "complete",
579	        progress: 1,
580	        renderedSeconds: duration,
581	        totalSeconds: duration,
582	      };
583	
584	      return {
585	        blob,
586	        duration,
587	        sampleRate: options.sampleRate,
588	        channels: 2,
589	      };
590	    },
591	
592	    cancel(): void {
593	      cancelled = true;
594	    },
595	  };
596	}
