1	/**
2	 * Synthesizer AudioWorklet processor.
3	 * Runs on the audio rendering thread — zero allocations in process().
4	 *
5	 * Architecture: 16 fixed voices, each with:
6	 * - 2 PolyBLEP oscillators
7	 * - Biquad filter (LP/HP/BP)
8	 * - ADSR amplitude envelope
9	 * - ADSR filter envelope
10	 * Shared: 2 LFOs, hardwired modulation matrix.
11	 *
12	 * INV-3/NFR-14: Zero-allocation process().
13	 * MIT-H4-5: Oldest-steal with 5ms crossfade.
14	 * MIT-H4-6: 2ms minimum release time.
15	 * R-STA-05: Legato mode with pitch glide.
16	 */
17	
18	import { createPolyBLEPOsc, type PolyBLEPOsc } from "./dsp/polyblep";
19	import {
20	  createADSREnvelope,
21	  type ADSREnvelope,
22	  type ADSRParams,
23	} from "./dsp/adsr";
24	import {
25	  computeBiquadCoeffs,
26	  createBiquadFilter,
27	  type BiquadFilter,
28	} from "./dsp/biquad-coeffs";
29	import { createLFO, type LFO } from "./dsp/lfo";
30	import {
31	  createVoiceAllocator,
32	  type VoiceAllocator,
33	  MAX_VOICES,
34	} from "./dsp/voice-allocator";
35	import {
36	  midiToFreq,
37	  WAVEFORM_TYPES,
38	  FILTER_TYPES,
39	  LFO_SHAPES,
40	  type SynthVoiceCommand,
41	  type SynthParameterMap,
42	  DEFAULT_SYNTH_PARAMS,
43	} from "./synth-types";
44	import {
45	  createModAccumulators,
46	  resetAccumulators,
47	  applyModRoute,
48	  type ModAccumulators,
49	  type WorkletModRoute,
50	  SOURCE_INDEX,
51	} from "./modulation-engine";
52	
53	// ─── AudioWorklet globals ───
54	declare const sampleRate: number;
55	declare class AudioWorkletProcessor {
56	  readonly port: MessagePort;
57	  constructor();
58	  process(
59	    inputs: Float32Array[][],
60	    outputs: Float32Array[][],
61	    parameters: Record<string, Float32Array>,
62	  ): boolean;
63	}
64	declare function registerProcessor(
65	  name: string,
66	  ctor: typeof AudioWorkletProcessor,
67	): void;
68	
69	// ─── Per-Voice State (pre-allocated) ───
70	
71	type VoiceData = {
72	  osc1: PolyBLEPOsc;
73	  osc2: PolyBLEPOsc;
74	  ampEnv: ADSREnvelope;
75	  filterEnv: ADSREnvelope;
76	  filter: BiquadFilter;
77	  targetFreq: number;
78	  currentFreq: number;
79	  velocity: number;
80	};
81	
82	function createVoiceData(): VoiceData {
83	  return {
84	    osc1: createPolyBLEPOsc("saw"),
85	    osc2: createPolyBLEPOsc("saw"),
86	    ampEnv: createADSREnvelope(),
87	    filterEnv: createADSREnvelope(),
88	    filter: createBiquadFilter("lowpass"),
89	    targetFreq: 440,
90	    currentFreq: 440,
91	    velocity: 0,
92	  };
93	}
94	
95	/** Safe access to pre-allocated arrays */
96	function at<T>(arr: T[], i: number): T {
97	  const val = arr[i];
98	  if (val === undefined) throw new Error("Index out of bounds");
99	  return val;
100	}
101	
102	class SynthProcessor extends AudioWorkletProcessor {
103	  private allocator: VoiceAllocator;
104	  private voiceData: VoiceData[];
105	  private lfo1: LFO;
106	  private lfo2: LFO;
107	  private params: SynthParameterMap;
108	  // Pre-allocated ADSR params (S2-3: avoid per-quantum allocation)
109	  private ampParams: ADSRParams;
110	  private filterParams: ADSRParams;
111	  private alive = true;
112	
113	  // Modulation matrix (pre-allocated, zero-allocation in process())
114	  private modRoutes: WorkletModRoute[] = [];
115	  private modSourceValues = new Float64Array(8); // Global source values
116	  private voiceSrcValues = new Float64Array(8); // Per-voice source values
117	  private modAccGlobal: ModAccumulators = createModAccumulators();
118	  private modAccVoice: ModAccumulators = createModAccumulators();
119	
120	  constructor() {
121	    super();
122	
123	    this.allocator = createVoiceAllocator();
124	    this.voiceData = Array.from({ length: MAX_VOICES }, () =>
125	      createVoiceData(),
126	    );
127	    this.lfo1 = createLFO("sine");
128	    this.lfo2 = createLFO("sine");
129	    this.params = { ...DEFAULT_SYNTH_PARAMS };
130	    this.ampParams = { attack: 0, decay: 0, sustain: 0, release: 0 };
131	    this.filterParams = { attack: 0, decay: 0, sustain: 0, release: 0 };
132	
133	    this.port.onmessage = (e: MessageEvent) => {
134	      this.handleMessage(e.data as SynthVoiceCommand);
135	    };
136	  }
137	
138	  private handleMessage(cmd: SynthVoiceCommand): void {
139	    switch (cmd.type) {
140	      case "noteOn": {
141	        const legato = cmd.legato;
142	        const idx = this.allocator.noteOn(cmd.note, cmd.velocity, legato);
143	        const voice = at(
144	          this.allocator.voices as unknown[],
145	          idx,
146	        ) as (typeof this.allocator.voices)[number];
147	
148	        // If voice is stealing, don't touch oscillators/envelopes yet —
149	        // the old voice continues rendering during the 5ms crossfade.
150	        // The processor will apply the new note when steal completes.
151	        if (voice.state === "stealing") {
152	          return;
153	        }
154	
155	        this.applyNoteOn(idx, cmd.note, cmd.velocity, legato);
156	        break;
157	      }
158	
159	      case "noteOff": {
160	        const idx = this.allocator.noteOff(cmd.note);
161	        if (idx >= 0) {
162	          const vd = at(this.voiceData, idx);
163	          vd.ampEnv.release();
164	          vd.filterEnv.release();
165	        }
166	        break;
167	      }
168	
169	      case "allNotesOff":
170	        // S1-4: Must also update allocator state
171	        for (let i = 0; i < MAX_VOICES; i++) {
172	          const voice = at(
173	            this.allocator.voices as unknown[],
174	            i,
175	          ) as (typeof this.allocator.voices)[number];
176	          if (voice.state === "active") {
177	            (voice as { state: string }).state = "releasing";
178	          } else if (voice.state === "stealing") {
179	            // Cancel pending steal — clear pending note and release
180	            (voice as { state: string }).state = "releasing";
181	            (voice as { pendingNote: number }).pendingNote = -1;
182	            (voice as { pendingVelocity: number }).pendingVelocity = 0;
183	          }
184	          at(this.voiceData, i).ampEnv.release();
185	          at(this.voiceData, i).filterEnv.release();
186	        }
187	        break;
188	
189	      case "setParam":
190	        this.setParamValue(cmd.key, cmd.value);
191	        break;
192	
193	      case "setModRoutes":
194	        this.modRoutes = cmd.routes;
195	        break;
196	
197	      case "setModSource": {
198	        // Update global mod source values (aftertouch, modwheel, pitchbend)
199	        const srcKey = cmd.source as keyof typeof SOURCE_INDEX;
200	        if (srcKey in SOURCE_INDEX) {
201	          this.modSourceValues[SOURCE_INDEX[srcKey]] = cmd.value;
202	        }
203	        break;
204	      }
205	    }
206	  }
207	
208	  /** Apply a note-on to voice oscillators and envelopes */
209	  private applyNoteOn(
210	    idx: number,
211	    note: number,
212	    velocity: number,
213	    legato: boolean,
214	  ): void {
215	    const vd = at(this.voiceData, idx);
216	
217	    const baseFreq = midiToFreq(note);
218	    vd.targetFreq = baseFreq;
219	    vd.velocity = velocity / 127;
220	
221	    if (!legato || vd.currentFreq === 0) {
222	      vd.currentFreq = baseFreq;
223	    }
224	
225	    if (!legato) {
226	      vd.osc1.reset();
227	      vd.osc2.reset();
228	      vd.filter.reset();
229	    }
230	
231	    vd.osc1.type = this.params.osc1Type;
232	    vd.osc2.type = this.params.osc2Type;
233	    vd.filter.type = this.params.filterType;
234	
235	    vd.ampEnv.gate(legato);
236	    vd.filterEnv.gate(legato);
237	  }
238	
239	  private setParamValue(key: string, value: number): void {
240	    switch (key) {
241	      case "osc1Type":
242	        this.params.osc1Type = WAVEFORM_TYPES[Math.round(value)] ?? "saw";
243	        break;
244	      case "osc2Type":
245	        this.params.osc2Type = WAVEFORM_TYPES[Math.round(value)] ?? "saw";
246	        break;
247	      case "filterType": {
248	        const ft = FILTER_TYPES[Math.round(value)] ?? "lowpass";
249	        this.params.filterType = ft;
250	        for (let i = 0; i < MAX_VOICES; i++) {
251	          at(this.voiceData, i).filter.type = ft;
252	        }
253	        break;
254	      }
255	      case "lfo1Shape":
256	        this.params.lfo1Shape = LFO_SHAPES[Math.round(value)] ?? "sine";
257	        this.lfo1.shape = this.params.lfo1Shape;
258	        break;
259	      case "lfo2Shape":
260	        this.params.lfo2Shape = LFO_SHAPES[Math.round(value)] ?? "sine";
261	        this.lfo2.shape = this.params.lfo2Shape;
262	        break;
263	      default:
264	        (this.params as Record<string, unknown>)[key] = value;
265	        break;
266	    }
267	  }
268	
269	  process(
270	    _inputs: Float32Array[][],
271	    outputs: Float32Array[][],
272	    _parameters: Record<string, Float32Array>,
273	  ): boolean {
274	    const output = outputs[0];
275	    if (!output) return this.alive;
276	
277	    const outL = output[0];
278	    const outR = output[1] ?? output[0];
279	    if (!outL || !outR) return this.alive;
280	
281	    const numSamples = outL.length;
282	    const sr = sampleRate;
283	    const p = this.params;
284	
285	    // Update pre-allocated ADSR params in-place (S2-3)
286	    this.ampParams.attack = p.ampAttack;
287	    this.ampParams.decay = p.ampDecay;
288	    this.ampParams.sustain = p.ampSustain;
289	    this.ampParams.release = p.ampRelease;
290	
291	    this.filterParams.attack = p.filterAttack;
292	    this.filterParams.decay = p.filterDecay;
293	    this.filterParams.sustain = p.filterSustain;
294	    this.filterParams.release = p.filterRelease;
295	
296	    // Pre-compute control-rate values (constant across quantum)
297	    const osc1OctMul = Math.pow(2, p.osc1Octave);
298	    const osc1DetMul = Math.pow(2, p.osc1Detune / 1200);
299	    const osc2OctMul = Math.pow(2, p.osc2Octave);
300	    const osc2DetMul = Math.pow(2, p.osc2Detune / 1200);
301	
302	    for (let s = 0; s < numSamples; s++) {
303	      // LFO rates incorporate modulation from previous sample (1-sample delay, inaudible)
304	      const lfo1Rate = Math.max(0.01, p.lfo1Rate + this.modAccGlobal.lfo1Rate);
305	      const lfo2Rate = Math.max(0.01, p.lfo2Rate + this.modAccGlobal.lfo2Rate);
306	      const lfo1Val = this.lfo1.process(lfo1Rate, sr);
307	      const lfo2Val = this.lfo2.process(lfo2Rate, sr);
308	
309	      // Update global source values for modulation (scaled by depth)
310	      this.modSourceValues[SOURCE_INDEX.lfo1] = lfo1Val * p.lfo1Depth;
311	      this.modSourceValues[SOURCE_INDEX.lfo2] = lfo2Val * p.lfo2Depth;
312	
313	      // Compute global modulation (from non-per-voice sources)
314	      resetAccumulators(this.modAccGlobal);
315	      for (let ri = 0; ri < this.modRoutes.length; ri++) {
316	        const route = at(this.modRoutes as unknown[], ri) as WorkletModRoute;
317	        // Global sources: lfo1, lfo2, aftertouch, modWheel, pitchBend
318	        const si = route.sourceIdx;
319	        if (
320	          si === SOURCE_INDEX.lfo1 ||
321	          si === SOURCE_INDEX.lfo2 ||
322	          si === SOURCE_INDEX.aftertouch ||
323	          si === SOURCE_INDEX.modWheel ||
324	          si === SOURCE_INDEX.pitchBend
325	        ) {
326	          applyModRoute(
327	            this.modAccGlobal,
328	            this.modSourceValues,
329	            si,
330	            route.destIdx,
331	            route.amount,
332	            route.bipolar,
333	          );
334	        }
335	      }
336	
337	      let mixL = 0;
338	      let mixR = 0;
339	
340	      for (let vi = 0; vi < MAX_VOICES; vi++) {
341	        const voice = at(this.allocator.voices as unknown[], vi) as {
342	          state: string;
343	          stealFadeGain: number;
344	        };
345	
346	        // S2-5: Early idle check before any DSP work
347	        if (voice.state === "idle") continue;
348	
349	        const vd = at(this.voiceData, vi);
350	
351	        // Check if envelope finished release — mark idle before processing
352	        if (vd.ampEnv.stage === "idle" && voice.state === "releasing") {
353	          this.allocator.markIdle(vi);
354	          continue;
355	        }
356	
357	        // Pitch glide (R-STA-05)
358	        if (p.glideTime > 0 && vd.currentFreq !== vd.targetFreq) {
359	          const glideCoeff = 1 - Math.exp(-1 / (p.glideTime * sr));
360	          vd.currentFreq += glideCoeff * (vd.targetFreq - vd.currentFreq);
361	        } else {
362	          vd.currentFreq = vd.targetFreq;
363	        }
364	
365	        const baseFreq = vd.currentFreq;
366	
367	        // Filter envelope (must process every sample to advance state)
368	        const filterEnvVal = vd.filterEnv.process(this.filterParams, sr);
369	        // Amplitude envelope
370	        const ampLevel = vd.ampEnv.process(this.ampParams, sr);
371	
372	        // Compute per-voice modulation
373	        resetAccumulators(this.modAccVoice);
374	        if (this.modRoutes.length > 0) {
375	          // Set per-voice source values
376	          this.voiceSrcValues[SOURCE_INDEX.ampEnv] = ampLevel;
377	          this.voiceSrcValues[SOURCE_INDEX.filterEnv] = filterEnvVal;
378	          this.voiceSrcValues[SOURCE_INDEX.velocity] = vd.velocity;
379	
380	          for (let ri = 0; ri < this.modRoutes.length; ri++) {
381	            const route = at(
382	              this.modRoutes as unknown[],
383	              ri,
