430	        // oscMix modulation crossfades: negative = more osc1, positive = more osc2
431	        const osc1Gain = Math.max(0, Math.min(1, 1 - modOscMix));
432	        const osc2Gain = Math.max(0, Math.min(1, 1 + modOscMix));
433	        let sample = osc1Out * osc1Gain + osc2Out * osc2Gain;
434	
435	        // Control-rate filter coefficients: recompute once per block per voice.
436	        // Trade-off: fast LFO modulation of cutoff uses only sample-0 values
