478	        mixL += sample;
479	        mixR += sample;
480	      }
481	
482	      // Process steal fades and get completed steals
483	      const completed = this.allocator.processStealFade(sr);
484	
485	      // S1-3: Apply pending notes for voices that completed steal crossfade
486	      for (let ci = 0; ci < completed.count; ci++) {
487	        const completedIdx = completed.data[ci];
488	        if (completedIdx !== undefined) {
