490	            this.allocator.voices as unknown[],
491	            completedIdx,
492	          ) as {
493	            note: number;
494	            velocity: number;
495	          };
496	          this.applyNoteOn(completedIdx, voice.note, voice.velocity, false);
497	        }
498	      }
499	
500	      outL[s] = mixL;
501	      outR[s] = mixR;
502	    }
503	
504	    return this.alive;
505	  }
506	}
