1	/**
2	 * ADSR envelope generator with exponential curves.
3	 * Runs per-sample in the AudioWorklet — zero allocations.
4	 *
5	 * MIT-H4-6: Minimum release time floor of 2ms.
6	 */
7	
8	export type ADSRStage = "idle" | "attack" | "decay" | "sustain" | "release";
9	
10	export type ADSRParams = {
11	  attack: number; // seconds (0..10)
12	  decay: number; // seconds (0..10)
13	  sustain: number; // level (0..1)
14	  release: number; // seconds (0..10)
15	};
16	
17	/** Minimum release time in seconds (MIT-H4-6) */
18	const MIN_RELEASE_S = 0.002;
19	
20	/**
21	 * Stateful ADSR envelope.
22	 * Call `process()` once per sample. Mutates internal state.
23	 */
24	export type ADSREnvelope = {
25	  stage: ADSRStage;
26	  level: number;
27	  /** Trigger note-on. If legato, continues from current level. */
28	  gate(legato: boolean): void;
29	  /** Trigger note-off. Begins release from current level. */
30	  release(): void;
31	  /** Advance one sample. Returns envelope level [0, 1]. */
32	  process(params: ADSRParams, sampleRate: number): number;
33	  /** Hard reset to idle. */
34	  reset(): void;
35	};
36	
37	export function createADSREnvelope(): ADSREnvelope {
38	  let stage: ADSRStage = "idle";
39	  let level = 0;
40	  // Exponential time constant: how many samples to reach ~63% of target
41	  function timeToCoeff(timeS: number, sampleRate: number): number {
42	    if (timeS <= 0) return 1;
43	    // Exponential approach coefficient per sample
44	    return 1 - Math.exp(-1 / (timeS * sampleRate));
45	  }
46	
47	  const env: ADSREnvelope = {
48	    get stage() {
49	      return stage;
50	    },
51	    get level() {
52	      return level;
53	    },
54	
55	    gate(legato: boolean): void {
56	      if (!legato) {
57	        level = 0;
58	      }
59	      stage = "attack";
60	    },
61	
62	    release(): void {
63	      if (stage === "idle") return;
64	      stage = "release";
65	    },
66	
67	    process(params: ADSRParams, sampleRate: number): number {
68	      switch (stage) {
69	        case "idle":
70	          level = 0;
71	          break;
72	
73	        case "attack": {
74	          const coeff = timeToCoeff(params.attack, sampleRate);
75	          // Approach 1.0 + overshoot target for natural curve
76	          level += coeff * (1.2 - level);
77	          if (level >= 1) {
78	            level = 1;
79	            stage = "decay";
80	          }
81	          break;
82	        }
83	
84	        case "decay": {
85	          const coeff = timeToCoeff(params.decay, sampleRate);
86	          level += coeff * (params.sustain - level);
87	          // Close enough to sustain level
88	          if (Math.abs(level - params.sustain) < 0.001) {
89	            level = params.sustain;
90	            stage = "sustain";
91	          }
92	          break;
93	        }
94	
95	        case "sustain":
96	          level = params.sustain;
97	          break;
98	
99	        case "release": {
100	          const releaseTime = Math.max(params.release, MIN_RELEASE_S);
101	          const coeff = timeToCoeff(releaseTime, sampleRate);
102	          level += coeff * (0 - level);
103	          if (level < 0.0001) {
104	            level = 0;
105	            stage = "idle";
106	          }
107	          break;
108	        }
109	      }
110	
111	      return level;
112	    },
113	
114	    reset(): void {
115	      stage = "idle";
116	      level = 0;
117	    },
118	  };
119	
120	  return env;
121	}
