5	
6	/** Interpolation mode between automation points */
7	export type InterpolationMode = "linear" | "curved";
8	
9	/** Automation playback/recording mode */
10	export type AutomationMode = "read" | "write" | "touch";
11	
12	/** A single automation breakpoint */
13	export type AutomationPoint = {
14	  readonly id: string;
15	  /** Time position in seconds on the arrangement timeline */
16	  readonly time: number;
17	  /** Normalized value 0..1 (mapped to parameter range externally) */
18	  readonly value: number;
19	  /** Interpolation mode to the NEXT point */
20	  readonly interpolation: InterpolationMode;
21	  /** Bezier curve tension for "curved" interpolation (-1..1, 0 = linear) */
22	  readonly curve: number;
23	};
