      const clip = clips[clipId];
      if (!clip) continue;
      if (isAudioClip(clip)) {
        audioClips.push({ clip, trackId: track.id });
      } else if (isMidiClip(clip)) {
        midiClips.push({ clip, trackId: track.id });
      }
    }
  }

  return { audioClips, midiClips };
}

