/**
 * Tests for the bounce engine.
 * Tests core logic: session duration, event scheduling, progress, cancellation.
 * Uses mock OfflineAudioContext since jsdom doesn't provide one.
 */

import { describe, it, expect, vi } from "vitest";
import {
  computeSessionBounds,
  buildEventTimeline,
  createBounceEngine,
} from "./bounce-engine";
import type { AudioClipModel, MidiClipModel, TrackModel } from "@state/track/types";
import type { BounceOptions } from "./types";

// ─── Test helpers ───

function makeTrack(overrides: Partial<TrackModel> = {}): TrackModel {
  return {
    id: "track-1",
    name: "Track 1",
    type: "audio",
    color: "#ff0000",
    muted: false,
    solo: false,
    armed: false,
    soloIsolate: false,
    volume: 1,
    pan: 0,
    clipIds: ["clip-1"],
    ...overrides,
  };
}

function makeAudioClip(overrides: Partial<AudioClipModel> = {}): AudioClipModel {
  return {
    type: "audio",
    id: "clip-1",
    trackId: "track-1",
    sourceId: "source-1",
    startTime: 0,
    sourceOffset: 0,
    duration: 5,
    gain: 1,
    fadeIn: 0,
    fadeOut: 0,
    name: "Clip 1",
    ...overrides,
  };
}

function makeMidiClip(overrides: Partial<MidiClipModel> = {}): MidiClipModel {
  return {
    type: "midi",
    id: "midi-clip-1",
    trackId: "track-2",
    startTime: 0,
    duration: 4,
    noteEvents: [
      { id: "n1", pitch: 60, velocity: 100, startTime: 0, duration: 1 },
      { id: "n2", pitch: 64, velocity: 80, startTime: 1, duration: 1 },
    ],
    name: "MIDI Clip",
    ...overrides,
  };
}

// ─── computeSessionBounds ───

describe("computeSessionBounds", () => {
  it("computes bounds from audio clips", () => {
    const clips = {
      "clip-1": makeAudioClip({ startTime: 2, duration: 5 }),
      "clip-2": makeAudioClip({ id: "clip-2", startTime: 10, duration: 3 }),
    };
    const tracks = [
      makeTrack({ clipIds: ["clip-1", "clip-2"] }),
    ];

    const bounds = computeSessionBounds(tracks, clips);
    expect(bounds.start).toBe(2);
    expect(bounds.end).toBe(13); // 10 + 3
  });

  it("includes MIDI clip bounds", () => {
    const clips = {
      "midi-1": makeMidiClip({ id: "midi-1", startTime: 1, duration: 4 }),
    };
    const tracks = [
      makeTrack({ id: "track-2", type: "instrument", clipIds: ["midi-1"] }),
    ];

    const bounds = computeSessionBounds(tracks, clips);
    expect(bounds.start).toBe(1);
    expect(bounds.end).toBe(5);
  });

  it("excludes muted tracks", () => {
    const clips = {
      "clip-1": makeAudioClip({ startTime: 0, duration: 10 }),
      "clip-2": makeAudioClip({ id: "clip-2", trackId: "track-2", startTime: 0, duration: 20 }),
    };
    const tracks = [
      makeTrack({ clipIds: ["clip-1"] }),
      makeTrack({ id: "track-2", clipIds: ["clip-2"], muted: true }),
    ];

    const bounds = computeSessionBounds(tracks, clips);
    expect(bounds.end).toBe(10); // Muted track excluded
  });

  it("returns zero bounds for empty session", () => {
    const bounds = computeSessionBounds([], {});
    expect(bounds.start).toBe(0);
    expect(bounds.end).toBe(0);
  });

  it("handles solo: only includes soloed tracks", () => {
    const clips = {
      "clip-1": makeAudioClip({ startTime: 0, duration: 5 }),
      "clip-2": makeAudioClip({ id: "clip-2", trackId: "track-2", startTime: 0, duration: 20 }),
    };
    const tracks = [
      makeTrack({ clipIds: ["clip-1"], solo: true }),
      makeTrack({ id: "track-2", clipIds: ["clip-2"] }),
    ];

    const bounds = computeSessionBounds(tracks, clips);
    expect(bounds.end).toBe(5); // Only soloed track
  });
});

// ─── buildEventTimeline ───

describe("buildEventTimeline", () => {
  it("collects audio clips for non-muted tracks", () => {
    const clips = {
      "clip-1": makeAudioClip(),
    };
    const tracks = [makeTrack()];
    const timeline = buildEventTimeline(tracks, clips);

    expect(timeline.audioClips.length).toBe(1);
    expect(timeline.audioClips[0]?.clip.id).toBe("clip-1");
  });

  it("excludes clips from muted tracks", () => {
    const clips = {
      "clip-1": makeAudioClip(),
    };
    const tracks = [makeTrack({ muted: true })];
    const timeline = buildEventTimeline(tracks, clips);

    expect(timeline.audioClips.length).toBe(0);
  });

  it("collects MIDI clips separately", () => {
    const clips = {
      "midi-1": makeMidiClip({ id: "midi-1" }),
    };
    const tracks = [
      makeTrack({ id: "track-2", type: "instrument", clipIds: ["midi-1"] }),
    ];
    const timeline = buildEventTimeline(tracks, clips);

    expect(timeline.midiClips.length).toBe(1);
    expect(timeline.midiClips[0]?.clip.id).toBe("midi-1");
  });

  it("handles solo-in-place: only audible tracks included", () => {
    const clips = {
      "clip-1": makeAudioClip(),
      "clip-2": makeAudioClip({ id: "clip-2", trackId: "track-2" }),
    };
    const tracks = [
      makeTrack({ solo: true, clipIds: ["clip-1"] }),
      makeTrack({ id: "track-2", clipIds: ["clip-2"] }),
    ];
    const timeline = buildEventTimeline(tracks, clips);

    expect(timeline.audioClips.length).toBe(1);
    expect(timeline.audioClips[0]?.clip.trackId).toBe("track-1");
  });
});

// ─── BounceEngine (integration with mocks) ───

describe("createBounceEngine", () => {
  // eslint-disable-next-line @typescript-eslint/explicit-function-return-type
  function createMockOfflineAudioContext(duration: number, sampleRate: number) {
    const numSamples = Math.ceil(duration * sampleRate);
    const renderedBuffer = {
      numberOfChannels: 2,
      length: numSamples,
      sampleRate,
      duration,
      getChannelData(ch: number): Float32Array {
        const data = new Float32Array(numSamples);
        if (ch === 0) {
          for (let i = 0; i < numSamples; i++) {
            data[i] = Math.sin((2 * Math.PI * 440 * i) / sampleRate) * 0.5;
          }
        }
        return data;
      },
    };

    return {
      sampleRate,
      length: numSamples,
      destination: { connect: vi.fn(), disconnect: vi.fn() },
      createGain: vi.fn().mockImplementation(() => ({
        gain: {
          value: 1,
          setValueAtTime: vi.fn(),
          linearRampToValueAtTime: vi.fn(),
          cancelScheduledValues: vi.fn(),
        },
        connect: vi.fn().mockReturnThis(),
        disconnect: vi.fn(),
      })),
      createAnalyser: vi.fn().mockImplementation(() => ({
        gain: { value: 1, setValueAtTime: vi.fn(), linearRampToValueAtTime: vi.fn() },
        connect: vi.fn().mockReturnThis(),
        disconnect: vi.fn(),
        fftSize: 2048,
      })),
      createStereoPanner: vi.fn().mockImplementation(() => ({
        pan: { value: 0 },
        connect: vi.fn().mockReturnThis(),
        disconnect: vi.fn(),
      })),
      createDynamicsCompressor: vi.fn().mockImplementation(() => ({
        threshold: { value: -1 },
        ratio: { value: 20 },
        knee: { value: 0 },
        attack: { value: 0.001 },
        release: { value: 0.01 },
        connect: vi.fn().mockReturnThis(),
        disconnect: vi.fn(),
      })),
      createBufferSource: vi.fn().mockImplementation(() => ({
        buffer: null as unknown,
        playbackRate: { value: 1, setValueAtTime: vi.fn() },
        connect: vi.fn().mockReturnThis(),
        disconnect: vi.fn(),
        start: vi.fn(),
        stop: vi.fn(),
        addEventListener: vi.fn(),
      })),
      createBiquadFilter: vi.fn().mockImplementation(() => ({
        type: "lowpass",
        frequency: { value: 350, setValueAtTime: vi.fn() },
        connect: vi.fn().mockReturnThis(),
        disconnect: vi.fn(),
      })),
      createBuffer: vi.fn().mockImplementation((_ch: number, len: number, sr: number) => ({
        numberOfChannels: 2,
        length: len,
        sampleRate: sr,
        getChannelData: (): Float32Array => new Float32Array(len),
        copyToChannel: vi.fn(),
      })),
      startRendering: vi.fn().mockResolvedValue(renderedBuffer),
      suspend: vi.fn().mockResolvedValue(undefined),
      resume: vi.fn(),
    };
  }

  it("yields progress updates during bounce", async () => {
    const clips = { "clip-1": makeAudioClip({ duration: 2 }) };
    const tracks = [makeTrack()];
    const mockBuffer = {
      numberOfChannels: 1,
      length: 44100,
      sampleRate: 44100,
      getChannelData: () => new Float32Array(44100),
    };

    const options: BounceOptions = {
      sampleRate: 44100,
      bitDepth: 16,
      range: { type: "full" },
      tracks,
      clips,
      automationLanes: [],
      masterLevel: 1,
      getBuffer: () => mockBuffer as unknown as AudioBuffer,
      instruments: new Map(),
    };

    const engine = createBounceEngine(
      (dur, sr) => createMockOfflineAudioContext(dur, sr) as unknown as OfflineAudioContext,
    );

    const progress: string[] = [];
    const gen = engine.bounce(options);
    const result = await drainGenerator(gen, (p) => progress.push(p.phase));

    expect(progress).toContain("preparing");
    expect(progress).toContain("encoding");
    expect(result.blob.type).toBe("audio/wav");
  });

  it("respects region range selection", async () => {
    const clips = {
      "clip-1": makeAudioClip({ startTime: 0, duration: 10 }),
    };
    const tracks = [makeTrack()];
    const mockBuffer = {
      numberOfChannels: 1,
      length: 44100,
      sampleRate: 44100,
      getChannelData: (): Float32Array => new Float32Array(44100),
    };

    const options: BounceOptions = {
      sampleRate: 44100,
      bitDepth: 16,
      range: { type: "region", start: 2, end: 5 },
      tracks,
      clips,
      automationLanes: [],
      masterLevel: 1,
      getBuffer: () => mockBuffer as unknown as AudioBuffer,
      instruments: new Map(),
    };

    const engine = createBounceEngine(
      (dur, sr) => createMockOfflineAudioContext(dur, sr) as unknown as OfflineAudioContext,
    );

    const result = await drainGenerator(engine.bounce(options));

    // Duration should be 3 seconds (5 - 2)
    expect(result.duration).toBe(3);
  });

  it("can be cancelled mid-bounce", async () => {
    const clips = { "clip-1": makeAudioClip({ duration: 60 }) };
    const tracks = [makeTrack()];
    const mockBuffer = {
      numberOfChannels: 1,
      length: 44100,
      sampleRate: 44100,
      getChannelData: (): Float32Array => new Float32Array(44100),
    };

    const options: BounceOptions = {
      sampleRate: 44100,
      bitDepth: 16,
      range: { type: "full" },
      tracks,
      clips,
      automationLanes: [],
      masterLevel: 1,
      getBuffer: () => mockBuffer as unknown as AudioBuffer,
      instruments: new Map(),
    };

    const engine = createBounceEngine(
      (dur, sr) => createMockOfflineAudioContext(dur, sr) as unknown as OfflineAudioContext,
    );

    const gen = engine.bounce(options);

    // Get first progress update
    const first = await gen.next();
    expect(first.done === true).toBe(false);

    // Cancel after first progress
    engine.cancel();

    const result = await drainGenerator(gen);

    // Cancellation should produce an empty blob
    expect(result.blob.size).toBe(0);
  });
});

/**
 * Tests for the offline synth renderer.
 * Renders MIDI note events to stereo Float32Array using synth DSP directly.
 */

import { describe, it, expect } from "vitest";
import { renderMidiClipToAudio } from "./synth-renderer";
import { DEFAULT_SYNTH_PARAMS } from "@audio/synth/synth-types";
import type { MIDINoteEvent } from "@state/track/types";

const SR = 44100;

function makeNote(
  pitch: number,
  velocity: number,
  startTime: number,
  duration: number,
): MIDINoteEvent {
  return {
    id: `note-${pitch}-${startTime}`,
    pitch,
    velocity,
    startTime,
    duration,
  };
}

describe("renderMidiClipToAudio", () => {
  it("returns stereo output with correct length", () => {
    const notes: MIDINoteEvent[] = [makeNote(60, 100, 0, 0.5)];
    const result = renderMidiClipToAudio(notes, 1.0, SR, DEFAULT_SYNTH_PARAMS);

    expect(result.left.length).toBe(SR); // 1 second
    expect(result.right.length).toBe(SR);
  });

  it("produces non-silent output for a note", () => {
    const notes: MIDINoteEvent[] = [makeNote(69, 100, 0, 0.5)]; // A4
    const result = renderMidiClipToAudio(notes, 1.0, SR, DEFAULT_SYNTH_PARAMS);

    // Should have audio signal (not all zeros)
    const maxAbs = result.left.reduce(
      (max, s) => Math.max(max, Math.abs(s)),
      0,
    );
    expect(maxAbs).toBeGreaterThan(0.01);
  });

  it("produces silence when no notes", () => {
    const result = renderMidiClipToAudio([], 1.0, SR, DEFAULT_SYNTH_PARAMS);

    const maxAbs = result.left.reduce(
      (max, s) => Math.max(max, Math.abs(s)),
      0,
    );
    expect(maxAbs).toBe(0);
  });

  it("handles multiple overlapping notes (polyphony)", () => {
    const notes: MIDINoteEvent[] = [
      makeNote(60, 100, 0, 0.5), // C4
      makeNote(64, 100, 0, 0.5), // E4
      makeNote(67, 100, 0, 0.5), // G4
    ];
    const result = renderMidiClipToAudio(notes, 1.0, SR, DEFAULT_SYNTH_PARAMS);

    // Should be louder than a single note
    const maxAbs = result.left.reduce(
      (max, s) => Math.max(max, Math.abs(s)),
      0,
    );
    expect(maxAbs).toBeGreaterThan(0.05);
  });

  it("respects note timing - note at 0.5s is silent before that", () => {
    const notes: MIDINoteEvent[] = [makeNote(69, 100, 0.5, 0.3)];
    const result = renderMidiClipToAudio(notes, 1.0, SR, DEFAULT_SYNTH_PARAMS);

    // First 0.4 seconds should be silence (with some margin for attack)
    const samplesBeforeNote = Math.floor(0.4 * SR);
    const firstPart = result.left.subarray(0, samplesBeforeNote);
    const maxAbsBefore = firstPart.reduce(
      (max, s) => Math.max(max, Math.abs(s)),
      0,
    );
    expect(maxAbsBefore).toBe(0);
  });

  it("applies velocity scaling", () => {
    const loudNote: MIDINoteEvent[] = [makeNote(69, 127, 0, 0.5)];
    const quietNote: MIDINoteEvent[] = [makeNote(69, 32, 0, 0.5)];

    const loudResult = renderMidiClipToAudio(
      loudNote, 1.0, SR, DEFAULT_SYNTH_PARAMS,
    );
    const quietResult = renderMidiClipToAudio(
      quietNote, 1.0, SR, DEFAULT_SYNTH_PARAMS,
    );

    const loudMax = loudResult.left.reduce(
      (max, s) => Math.max(max, Math.abs(s)),
      0,
    );
    const quietMax = quietResult.left.reduce(
      (max, s) => Math.max(max, Math.abs(s)),
      0,
    );

    expect(loudMax).toBeGreaterThan(quietMax);
  });

  it("produces finite values (no NaN or Infinity)", () => {
    const notes: MIDINoteEvent[] = [
      makeNote(127, 127, 0, 0.5), // Very high note
      makeNote(21, 127, 0, 0.5), // Very low note
    ];
    const result = renderMidiClipToAudio(notes, 1.0, SR, DEFAULT_SYNTH_PARAMS);

    const hasNaN = result.left.some((s) => !isFinite(s));
    expect(hasNaN).toBe(false);
  });

  it("applies note-off release envelope", () => {
    // Short note with release - should have audio after note-off
    const params = { ...DEFAULT_SYNTH_PARAMS, ampRelease: 0.5 };
    const notes: MIDINoteEvent[] = [makeNote(69, 100, 0, 0.1)];
    const result = renderMidiClipToAudio(notes, 1.0, SR, params);

    // At 0.2s (after 0.1s note + some release), there should still be signal
    const sampleAt200ms = Math.floor(0.2 * SR);
    const levelAt200ms = Math.abs(result.left[sampleAt200ms] ?? 0);
    expect(levelAt200ms).toBeGreaterThan(0);
  });
});

