/**
 * Offline synth renderer: renders MIDI note events to stereo audio
 * using the synth DSP functions directly (no AudioWorklet dependency).
 *
 * This mirrors the SynthProcessor logic but runs synchronously,
 * producing Float32Arrays suitable for use as AudioBufferSourceNodes
 * in the offline bounce context.
 */

import type { MIDINoteEvent } from "@state/track/types";
import type { SynthParameterMap } from "@audio/synth/synth-types";
import { midiToFreq } from "@audio/synth/synth-types";
import { createPolyBLEPOsc } from "@audio/synth/dsp/polyblep";
import { createADSREnvelope, type ADSRParams } from "@audio/synth/dsp/adsr";
import {
  computeBiquadCoeffs,
  createBiquadFilter,
} from "@audio/synth/dsp/biquad-coeffs";
import { createLFO } from "@audio/synth/dsp/lfo";

const MAX_VOICES = 16;

type OfflineVoice = {
  active: boolean;
  releasing: boolean;
  note: number;
  osc1: ReturnType<typeof createPolyBLEPOsc>;
  osc2: ReturnType<typeof createPolyBLEPOsc>;
  ampEnv: ReturnType<typeof createADSREnvelope>;
  filterEnv: ReturnType<typeof createADSREnvelope>;
  filter: ReturnType<typeof createBiquadFilter>;
  targetFreq: number;
  currentFreq: number;
  velocity: number;
};

function createOfflineVoice(): OfflineVoice {
  return {
    active: false,
    releasing: false,
    note: -1,
    osc1: createPolyBLEPOsc("saw"),
    osc2: createPolyBLEPOsc("saw"),
    ampEnv: createADSREnvelope(),
    filterEnv: createADSREnvelope(),
    filter: createBiquadFilter("lowpass"),
    targetFreq: 440,
    currentFreq: 440,
    velocity: 0,
  };
}

type NoteEvent = {
  sample: number;
  type: "on" | "off";
  note: number;
  velocity: number;
};

export type RenderedAudio = {
  readonly left: Float32Array;
  readonly right: Float32Array;
};

/**
 * Render MIDI note events to stereo audio using synth DSP.
 * @param notes - MIDI note events (startTime relative to clip start)
 * @param duration - Total duration to render in seconds
 * @param sampleRate - Sample rate
 * @param params - Synth parameter snapshot
 */
export function renderMidiClipToAudio(
  notes: readonly MIDINoteEvent[],
  duration: number,
  sampleRate: number,
  params: SynthParameterMap,
): RenderedAudio {
  const totalSamples = Math.ceil(duration * sampleRate);
  const left = new Float32Array(totalSamples);
  const right = new Float32Array(totalSamples);

  if (notes.length === 0) return { left, right };

  // Build sorted event list (note-ons and note-offs)
  const events: NoteEvent[] = [];
  for (const note of notes) {
    const onSample = Math.floor(note.startTime * sampleRate);
    const offSample = Math.floor((note.startTime + note.duration) * sampleRate);
    events.push({ sample: onSample, type: "on", note: note.pitch, velocity: note.velocity });
    events.push({ sample: offSample, type: "off", note: note.pitch, velocity: 0 });
  }
  events.sort((a, b) => a.sample - b.sample || (a.type === "off" ? -1 : 1));

  // Pre-allocate voices
  const voices: OfflineVoice[] = Array.from({ length: MAX_VOICES }, () =>
    createOfflineVoice(),
  );

  // LFOs (shared across all voices)
  const lfo1 = createLFO(params.lfo1Shape);
  const lfo2 = createLFO(params.lfo2Shape);

  // ADSR params (pre-allocated)
  const ampParams: ADSRParams = {
    attack: params.ampAttack,
    decay: params.ampDecay,
    sustain: params.ampSustain,
    release: params.ampRelease,
  };
  const filterParams: ADSRParams = {
    attack: params.filterAttack,
    decay: params.filterDecay,
    sustain: params.filterSustain,
    release: params.filterRelease,
  };

  // Pre-compute constants
  const osc1OctMul = Math.pow(2, params.osc1Octave);
  const osc1DetMul = Math.pow(2, params.osc1Detune / 1200);
  const osc2OctMul = Math.pow(2, params.osc2Octave);
  const osc2DetMul = Math.pow(2, params.osc2Detune / 1200);

  let eventIdx = 0;

  for (let s = 0; s < totalSamples; s++) {
    // Process events at this sample
    while (eventIdx < events.length) {
      const evt = events[eventIdx];
      if (!evt || evt.sample > s) break;

      if (evt.type === "on") {
        allocateNoteOn(voices, evt.note, evt.velocity, params);
      } else {
        releaseNote(voices, evt.note);
      }
      eventIdx++;
    }

    // LFO processing
    const lfo1Val = lfo1.process(params.lfo1Rate, sampleRate) * params.lfo1Depth;
    const lfo2Val = lfo2.process(params.lfo2Rate, sampleRate) * params.lfo2Depth;
    // Unused but kept for parity with processor — lfo modulation can be added later
    void lfo1Val;
    void lfo2Val;

    let mixL = 0;
    let mixR = 0;

    for (let vi = 0; vi < MAX_VOICES; vi++) {
      const v = voices[vi];
      if (!v || !v.active) continue;

      // Check if release finished
      if (v.ampEnv.stage === "idle" && v.releasing) {
        v.active = false;
        v.releasing = false;
        continue;
      }

      // Pitch glide
      if (params.glideTime > 0 && v.currentFreq !== v.targetFreq) {
        const glideCoeff = 1 - Math.exp(-1 / (params.glideTime * sampleRate));
        v.currentFreq += glideCoeff * (v.targetFreq - v.currentFreq);
      } else {
        v.currentFreq = v.targetFreq;
      }

      const baseFreq = v.currentFreq;

      // Envelopes
      const filterEnvVal = v.filterEnv.process(filterParams, sampleRate);
      const ampLevel = v.ampEnv.process(ampParams, sampleRate);

      // Oscillators
      const freq1 = baseFreq * osc1OctMul * osc1DetMul;
      const freq2 = baseFreq * osc2OctMul * osc2DetMul;
      const osc1Out = v.osc1.next(freq1, sampleRate) * params.osc1Level;
      const osc2Out = v.osc2.next(freq2, sampleRate) * params.osc2Level;
      let sample = osc1Out + osc2Out;

      // Filter (recompute coefficients periodically for efficiency)
      if (s % 128 === 0) {
        const cutoffModSt = filterEnvVal * params.filterEnvDepth;
        const modulatedCutoff = params.filterCutoff * Math.pow(2, cutoffModSt / 12);
        const clampedCutoff = Math.min(Math.max(modulatedCutoff, 20), sampleRate / 2 - 100);
        computeBiquadCoeffs(
          params.filterType,
          clampedCutoff,
          params.filterResonance,
          sampleRate,
          v.filter.coeffs,
        );
      }

      sample = v.filter.process(sample);

      // Velocity -> amplitude
      const velAmp = 0.5 + v.velocity * 0.5;
      sample *= ampLevel * velAmp * params.masterGain;

      // Clamp to prevent overflow
      if (!isFinite(sample)) sample = 0;

      mixL += sample;
      mixR += sample;
    }

    left[s] = mixL;
    right[s] = mixR;
  }

  return { left, right };
}

/** Allocate a voice for a new note (oldest-steal if full) */
function allocateNoteOn(
  voices: OfflineVoice[],
  note: number,
  velocity: number,
  params: SynthParameterMap,
): void {
  // Find free voice
  let idx = -1;
  for (let i = 0; i < MAX_VOICES; i++) {
    if (!voices[i]?.active) {
      idx = i;
      break;
    }
  }

  // Steal oldest releasing voice if no free voice
  if (idx === -1) {
    for (let i = 0; i < MAX_VOICES; i++) {
      if (voices[i]?.releasing) {
        idx = i;
        break;
      }
    }
  }

  // Steal first voice as last resort
  if (idx === -1) idx = 0;

  const v = voices[idx];
  if (!v) return;

  const freq = midiToFreq(note);
  v.active = true;
  v.releasing = false;
  v.note = note;
  v.velocity = velocity / 127;
  v.targetFreq = freq;
  v.currentFreq = freq;

  v.osc1.reset();
  v.osc2.reset();
  v.filter.reset();
  v.osc1.type = params.osc1Type;
  v.osc2.type = params.osc2Type;
  v.filter.type = params.filterType;
  v.ampEnv.gate(false);
  v.filterEnv.gate(false);
}

/** Release all voices playing this note */
function releaseNote(voices: OfflineVoice[], note: number): void {
  for (let i = 0; i < MAX_VOICES; i++) {
    const v = voices[i];
    if (v && v.active && !v.releasing && v.note === note) {
      v.releasing = true;
      v.ampEnv.release();
      v.filterEnv.release();
    }
  }
}

/**
 * Tests for WAV encoder.
 * Verifies correct WAV header, PCM encoding at different bit depths,
 * stereo interleaving, and chunk-based assembly.
 */

import { describe, it, expect } from "vitest";
import {
  encodeWav,
  encodeWavHeader,
  encodePcmChunk,
  assembleWav,
} from "./wav-encoder";

/** Create a simple mono sine wave buffer */
function makeSineBuffer(
  length: number,
  frequency: number,
  sampleRate: number,
): Float32Array {
  const buf = new Float32Array(length);
  for (let i = 0; i < length; i++) {
    buf[i] = Math.sin((2 * Math.PI * frequency * i) / sampleRate);
  }
  return buf;
}

describe("encodeWav", () => {
  it("produces a valid WAV file with correct RIFF header", () => {
    const left = new Float32Array([0, 0.5, 1, 0.5, 0, -0.5, -1, -0.5]);
    const right = new Float32Array([0, 0.5, 1, 0.5, 0, -0.5, -1, -0.5]);
    const blob = encodeWav([left, right], 44100, 16);

    // WAV = 44 byte header + data
    // 8 samples * 2 channels * 2 bytes/sample = 32 bytes data
    expect(blob.size).toBe(44 + 32);
    expect(blob.type).toBe("audio/wav");
  });

  it("encodes 16-bit PCM correctly", () => {
    // Single sample at 1.0 should be 32767 in 16-bit signed
    const left = new Float32Array([1.0]);
    const right = new Float32Array([1.0]);
    const blob = encodeWav([left, right], 44100, 16);

    expect(blob.size).toBe(44 + 4); // header + 2 channels * 2 bytes
  });

  it("encodes 24-bit PCM correctly", () => {
    const left = new Float32Array([0.5]);
    const right = new Float32Array([-0.5]);
    const blob = encodeWav([left, right], 44100, 24);

    // 1 sample * 2 channels * 3 bytes = 6 bytes data
    expect(blob.size).toBe(44 + 6);
  });

  it("encodes 32-bit float PCM correctly", () => {
    const left = new Float32Array([0.75]);
    const right = new Float32Array([-0.25]);
    const blob = encodeWav([left, right], 44100, 32);

    // 1 sample * 2 channels * 4 bytes = 8 bytes data
    expect(blob.size).toBe(44 + 8);
  });

  it("handles mono input (single channel)", () => {
    const mono = new Float32Array([0, 0.5, 1.0, -1.0]);
    const blob = encodeWav([mono], 44100, 16);

    // 4 samples * 1 channel * 2 bytes = 8 bytes data
    expect(blob.size).toBe(44 + 8);
  });

  it("clamps values exceeding [-1, 1] range", () => {
    const left = new Float32Array([2.0, -2.0]);
    const right = new Float32Array([1.5, -1.5]);
    const blob = encodeWav([left, right], 44100, 16);

    // Should not throw, values are clamped
    expect(blob.size).toBe(44 + 8);
  });

  it("handles empty input gracefully", () => {
    const left = new Float32Array(0);
    const right = new Float32Array(0);
    const blob = encodeWav([left, right], 44100, 16);

    // Just the header, no data
    expect(blob.size).toBe(44);
  });
});

describe("encodeWavHeader", () => {
  it("writes correct RIFF/WAVE markers", async () => {
    const header = encodeWavHeader(2, 44100, 16, 1000);
    const view = new DataView(header);

    // "RIFF" at offset 0
    expect(String.fromCharCode(view.getUint8(0), view.getUint8(1), view.getUint8(2), view.getUint8(3)))
      .toBe("RIFF");

    // "WAVE" at offset 8
    expect(String.fromCharCode(view.getUint8(8), view.getUint8(9), view.getUint8(10), view.getUint8(11)))
      .toBe("WAVE");

    // "fmt " at offset 12
    expect(String.fromCharCode(view.getUint8(12), view.getUint8(13), view.getUint8(14), view.getUint8(15)))
      .toBe("fmt ");

    // "data" at offset 36
    expect(String.fromCharCode(view.getUint8(36), view.getUint8(37), view.getUint8(38), view.getUint8(39)))
      .toBe("data");
  });

  it("writes correct channel count and sample rate", () => {
    const header = encodeWavHeader(2, 48000, 24, 500);
    const view = new DataView(header);

    // numChannels at offset 22
    expect(view.getUint16(22, true)).toBe(2);
    // sampleRate at offset 24
    expect(view.getUint32(24, true)).toBe(48000);
  });

  it("writes correct byte rate and block align for 16-bit stereo", () => {
    const header = encodeWavHeader(2, 44100, 16, 100);
    const view = new DataView(header);

    // byteRate = sampleRate * numChannels * bytesPerSample
    expect(view.getUint32(28, true)).toBe(44100 * 2 * 2);
    // blockAlign = numChannels * bytesPerSample
    expect(view.getUint16(32, true)).toBe(4);
    // bitsPerSample
    expect(view.getUint16(34, true)).toBe(16);
  });

  it("computes correct file size in RIFF header", () => {
    const dataSize = 44100 * 2 * 2; // 1 second, stereo, 16-bit
    const header = encodeWavHeader(2, 44100, 16, 44100);
    const view = new DataView(header);

    // RIFF chunk size = file size - 8 = (44 + dataSize) - 8
    expect(view.getUint32(4, true)).toBe(44 + dataSize - 8);
    // data chunk size
    expect(view.getUint32(40, true)).toBe(dataSize);
  });

  it("uses format code 1 (PCM) for 16-bit", () => {
    const header = encodeWavHeader(2, 44100, 16, 100);
    const view = new DataView(header);
    expect(view.getUint16(20, true)).toBe(1); // PCM
  });

  it("uses format code 3 (IEEE float) for 32-bit", () => {
    const header = encodeWavHeader(2, 44100, 32, 100);
    const view = new DataView(header);
    expect(view.getUint16(20, true)).toBe(3); // IEEE float
  });
});

describe("encodePcmChunk", () => {
  it("interleaves stereo samples correctly at 16-bit", () => {
    const left = new Float32Array([1.0, -1.0]);
    const right = new Float32Array([0.5, -0.5]);
    const chunk = encodePcmChunk([left, right], 16);

    const view = new DataView(chunk);
    // Sample 0: L=32767, R=16384 (0.5 * 32767 = 16383.5, rounds to 16384)
    expect(view.getInt16(0, true)).toBe(32767);
    expect(view.getInt16(2, true)).toBe(16384);
    // Sample 1: L=-32768, R=-16384
    expect(view.getInt16(4, true)).toBe(-32768);
    expect(view.getInt16(6, true)).toBe(-16384);
  });

  it("encodes 24-bit samples as 3 bytes little-endian", () => {
    const left = new Float32Array([1.0]);
    const right = new Float32Array([-1.0]);
    const chunk = encodePcmChunk([left, right], 24);

    expect(chunk.byteLength).toBe(6); // 1 sample * 2 channels * 3 bytes
    const bytes = new Uint8Array(chunk);
    // 1.0 -> 8388607 (0x7FFFFF) in 24-bit
    expect(bytes[0]).toBe(0xFF);
    expect(bytes[1]).toBe(0xFF);
    expect(bytes[2]).toBe(0x7F);
  });

  it("encodes 32-bit float samples directly", () => {
    const left = new Float32Array([0.75]);
    const right = new Float32Array([-0.25]);
    const chunk = encodePcmChunk([left, right], 32);

    const view = new DataView(chunk);
    expect(view.getFloat32(0, true)).toBeCloseTo(0.75);
    expect(view.getFloat32(4, true)).toBeCloseTo(-0.25);
  });
});

describe("assembleWav (chunked encoding)", () => {
  it("produces identical output to single-pass encodeWav", () => {
    const sampleRate = 44100;
    const numSamples = 1000;
    const left = makeSineBuffer(numSamples, 440, sampleRate);
    const right = makeSineBuffer(numSamples, 880, sampleRate);

    // Single-pass
    const singlePass = encodeWav([left, right], sampleRate, 16);

    // Chunked: split into 3 chunks
    const chunkSize = 400;
    const chunks: ArrayBuffer[] = [];
    for (let i = 0; i < numSamples; i += chunkSize) {
      const end = Math.min(i + chunkSize, numSamples);
      chunks.push(encodePcmChunk(
        [left.subarray(i, end), right.subarray(i, end)],
        16,
      ));
    }
    const assembled = assembleWav(
      encodeWavHeader(2, sampleRate, 16, numSamples),
      chunks,
    );

    expect(assembled.size).toBe(singlePass.size);
  });

  it("handles single chunk correctly", () => {
    const left = new Float32Array([0.5, -0.5]);
    const right = new Float32Array([0.25, -0.25]);
    const header = encodeWavHeader(2, 44100, 16, 2);
    const chunk = encodePcmChunk([left, right], 16);
    const blob = assembleWav(header, [chunk]);

    expect(blob.size).toBe(44 + 8); // header + 2 samples * 2 ch * 2 bytes
    expect(blob.type).toBe("audio/wav");
  });
});

/**
 * Tests for the bounce engine.
 * Tests core logic: session duration, event scheduling, progress, cancellation.
 * Uses mock OfflineAudioContext since jsdom doesn't provide one.
 */

import { describe, it, expect, vi } from "vitest";
import {
  computeSessionBounds,
  buildEventTimeline,
  createBounceEngine,
} from "./bounce-engine";
import type { AudioClipModel, MidiClipModel, TrackModel } from "@state/track/types";
import type { BounceOptions, BounceProgress, BounceResult } from "./types";

// ─── Test helpers ───

/** Drain an async generator, collecting the return value */
async function drainGenerator(
  gen: AsyncGenerator<BounceProgress, BounceResult>,
  onYield?: (value: BounceProgress) => void,
): Promise<BounceResult> {
  for (;;) {
    const next = await gen.next();
    if (next.done === true) return next.value;
    onYield?.(next.value);
  }
}

function makeTrack(overrides: Partial<TrackModel> = {}): TrackModel {
  return {
    id: "track-1",
    name: "Track 1",
    type: "audio",
    color: "#ff0000",
    muted: false,
    solo: false,
    armed: false,
    soloIsolate: false,
    volume: 1,
    pan: 0,
    clipIds: ["clip-1"],
    ...overrides,
  };
}

function makeAudioClip(overrides: Partial<AudioClipModel> = {}): AudioClipModel {
  return {
    type: "audio",
    id: "clip-1",
    trackId: "track-1",
    sourceId: "source-1",
    startTime: 0,
    sourceOffset: 0,
    duration: 5,
    gain: 1,
    fadeIn: 0,
    fadeOut: 0,
    name: "Clip 1",
    ...overrides,
  };
}

function makeMidiClip(overrides: Partial<MidiClipModel> = {}): MidiClipModel {
  return {
    type: "midi",
    id: "midi-clip-1",
    trackId: "track-2",
    startTime: 0,
    duration: 4,
    noteEvents: [
      { id: "n1", pitch: 60, velocity: 100, startTime: 0, duration: 1 },
      { id: "n2", pitch: 64, velocity: 80, startTime: 1, duration: 1 },
    ],
    name: "MIDI Clip",
    ...overrides,
  };
}

// ─── computeSessionBounds ───

describe("computeSessionBounds", () => {
  it("computes bounds from audio clips", () => {
    const clips = {
      "clip-1": makeAudioClip({ startTime: 2, duration: 5 }),
      "clip-2": makeAudioClip({ id: "clip-2", startTime: 10, duration: 3 }),
    };
    const tracks = [
      makeTrack({ clipIds: ["clip-1", "clip-2"] }),
    ];

    const bounds = computeSessionBounds(tracks, clips);
    expect(bounds.start).toBe(2);
    expect(bounds.end).toBe(13); // 10 + 3
  });

  it("includes MIDI clip bounds", () => {
    const clips = {
      "midi-1": makeMidiClip({ id: "midi-1", startTime: 1, duration: 4 }),
    };
    const tracks = [
      makeTrack({ id: "track-2", type: "instrument", clipIds: ["midi-1"] }),
    ];

    const bounds = computeSessionBounds(tracks, clips);
    expect(bounds.start).toBe(1);
    expect(bounds.end).toBe(5);
  });

  it("excludes muted tracks", () => {
    const clips = {
      "clip-1": makeAudioClip({ startTime: 0, duration: 10 }),
      "clip-2": makeAudioClip({ id: "clip-2", trackId: "track-2", startTime: 0, duration: 20 }),
    };
    const tracks = [
      makeTrack({ clipIds: ["clip-1"] }),
      makeTrack({ id: "track-2", clipIds: ["clip-2"], muted: true }),
    ];

    const bounds = computeSessionBounds(tracks, clips);
    expect(bounds.end).toBe(10); // Muted track excluded
  });

  it("returns zero bounds for empty session", () => {
    const bounds = computeSessionBounds([], {});
    expect(bounds.start).toBe(0);
    expect(bounds.end).toBe(0);
  });

  it("handles solo: only includes soloed tracks", () => {
    const clips = {
      "clip-1": makeAudioClip({ startTime: 0, duration: 5 }),
      "clip-2": makeAudioClip({ id: "clip-2", trackId: "track-2", startTime: 0, duration: 20 }),
    };
    const tracks = [
      makeTrack({ clipIds: ["clip-1"], solo: true }),
      makeTrack({ id: "track-2", clipIds: ["clip-2"] }),
    ];

    const bounds = computeSessionBounds(tracks, clips);
    expect(bounds.end).toBe(5); // Only soloed track
  });
});

