// Phase: Preparing
yield {
  phase: "preparing",
  progress: 0,
  renderedSeconds: 0,
  totalSeconds: 0,
};

if (state.cancelled) return emptyResult;

// Determine render range
const sessionBounds = computeSessionBounds(options.tracks, options.clips);
let rangeStart: number;
let rangeEnd: number;

if (options.range.type === "region") {
  rangeStart = options.range.start;
  rangeEnd = options.range.end;
} else {
  rangeStart = sessionBounds.start;
  rangeEnd = sessionBounds.end;
}

const duration = Math.max(0, rangeEnd - rangeStart);
if (duration === 0) return emptyResult;

// Build event timeline
const timeline = buildEventTimeline(options.tracks, options.clips);
const audibleIds = getAudibleTrackIds(options.tracks);

// Phase: Rendering
yield {
  phase: "rendering",
  progress: 0.1,
  renderedSeconds: 0,
  totalSeconds: duration,
};

// Create OfflineAudioContext
const ctx = contextFactory(duration, options.sampleRate);

// Build offline mixer graph
const mixer = buildOfflineMixer(ctx, options.tracks, options.masterLevel, audibleIds);

// Schedule audio clips
scheduleAudioClips(ctx, timeline.audioClips, mixer, rangeStart, options.getBuffer);

// Schedule MIDI clips (pre-rendered synth)
scheduleMidiClips(ctx, timeline.midiClips, mixer, rangeStart, options.instruments);

// Schedule drum clips
scheduleDrumClips(ctx, timeline.midiClips, mixer, rangeStart, options.instruments);

// Schedule automation
scheduleAutomation(ctx, options.automationLanes, mixer, rangeStart, duration);

if (state.cancelled) return emptyResult;

// Render
const renderedBuffer = await ctx.startRendering();

yield {
  phase: "rendering",
  progress: 0.7,
  renderedSeconds: duration,
  totalSeconds: duration,
};

if (state.cancelled) return emptyResult;

// Phase: Encoding
yield {
  phase: "encoding",
  progress: 0.8,
  renderedSeconds: duration,
  totalSeconds: duration,
};

const blob = encodeRenderedBuffer(renderedBuffer, options.bitDepth);

